INSERT INTO `ps_category_lang` (`id_category`, `id_shop`, `id_lang`, `name`, `description`, `additional_description`, `link_rewrite`, `meta_title`, `meta_keywords`, `meta_description`) VALUES
(1, 1, 1, 'Racine', '', '', 'racine', '', '', ''),
(2, 1, 1, 'Accueil', '', '', 'accueil', '', '', ''),
(43, 1, 1, 'Chambres à Coucher', '<p>La chambre à coucher doit être une pièce où règnent le calme et la sérénité, une pièce qui vous détend, où vous pouvez lire ou travailler tranquillement. Nous avons sélectionné pour vous des meubles de qualité ; lits, chevets, garde-robes, commodes, mais aussi placards et bibliothèques. Créez la chambre à coucher qui vous ressemble grâce à nos styles variés et laissez-vous séduire par notre large gamme de meubles de qualité.</p>', NULL, 'chambres-a-coucher', 'Chambres à Coucher - l\'art du meuble Rades', 'Chambre a coucher,lits,table de nuit,gardes robe,penderie,rangement,chiffonnière', 'Chambre a coucher lits table de nuit gardes robe penderie capitonne rangement chiffonnière   '),
(44, 1, 1, 'Chambres D\'enfant', '<p>En surfant sur www.lart-du-meuble.tn, vous trouverez des chambres à coucher complètes qui continueront à évoluer en même temps que votre enfant. Modulables, il vous suffira de changer la taille du lit et vous pourrez conserver le mobilier très longtemps. Votre commande vous parviendra dans les plus brefs délais ! Il ne vous reste plus qu\'à choisir le modèle de vos rêves pour offrir à votre enfant des nuits remplies de jolis rêves.</p>', '', 'chambres-d-enfant', 'chambre d\'enfant - Lit - nuit - chiffonnière - l\'art du meuble rades', 'lit,chambre d\'enfant ,table de nuit ,garde robe ,dressing,bureau,ranfement,rengement,chiffonnière ,table enfant', 'chambre d\'enfant - Lit - nuit - chiffonnière - l\'art du meuble rades'),
(45, 1, 1, 'Eléments d\'entrée', '<p>Le mobilier que vous trouverez dans cette catégorie est présenté dans une salle de séjour. Certaines de ces étagères ou armoires peuvent très bien trouver leur place dans une autre pièce telle qu\'une chambre, un vestibule ou autre. A vous d\'être créatif en choisissant le coloris et le style de votre meuble TV, afin qu\'il s\'accorde à votre décoration initiale</p>', NULL, 'elements-d-entree', 'element d’entrée - l\'art du meuble rades ', 'élément d’entrée,porte manteau, rangement,element ,porte chaussure,decoration', 'élément d’entrée porte manteau rangement element porte chaussure    '),
(46, 1, 1, 'Portes chaussures', '<p>Finies les chaussures qui traînent dans la maison. Cette armoire à chaussures vous facilitera énormément le rangement. Idéale pour un hall d\'entrée, salon, haull ... </p>', NULL, 'portes-chaussures', 'Porte Chaussure - L\'art du meuble', 'porte chaussure,rangement,element,decoration', 'porte chaussure  rangement element '),
(47, 1, 1, 'Matelas', '<p>Si vous cherchez un matelas 1 ou 2 personnes pour vous permettre de passer des nuits confortablement installé, n\'hésitez pas à parcourir le site lart du meuble.tn , vous aurez le choix entre une large gamme de produits. Un matelas confortable pour des nuits reposantes</p>\n<p>Quelles sont vos exigences en matière de soutien, de fermeté, d\'épaisseur ? Préférez-vous un modèle moelleux dans lequel votre corps se lovera ou bien un un matelas plus ferme pour soutenir votre dos ? La variété de la gamme devrait vous permettre de trouver le matelas parfait. Un matelas 1 ou 2 personnes à choisir selon vos besoins</p>\n<p>Après avoir précisé les critères importants cités plus haut, il vous restera à déterminer le type de matelas qu\'il vous faut, c\'est-à-dire un matelas pour enfant ou pour un adulte, un matelas 2 personnes, un matelas mousse ou un matelas Royale par exemple... A ressorts ensachés ou non, en polyéther de premier choix, à micro-ressorts... Vous trouverez de tout et le rapport qualité-prix est exemplaire.</p>', NULL, 'matelas', 'matelas - l\'art du meuble rades ', 'économie,édredon,cataplasme,coite,couchette,coussin,grabat,paillasse,confortex', 'économie édredon cataplasme coite couche couchette couette coussin grabat paillasse'),
(48, 1, 1, 'Salons massif', '<p>Les mille et un choix de lart du meuble vous permettent de personnaliser vos mobiliers! Rendez votre mobilier de salon unique en optant pour le tissu ou la couleur de tissu qui vous convient et qui s’harmonisera avec votre décor! Ou encore, choisissez le style de pattes et la couleur de votre prochain mobilier de sejour! Pour des créations du tunisen et d’ailleurs, venez chez Lart du meuble rades! Vous offrir la liberté de choisir, c’est notre spécialité avec les meubles.</p>', NULL, 'salons-massif', 'séjour - l\'art du meuble rades ', 'bal,banneton,boudoir,bringue,cercle,demeure,entourage,exposition,galerie,living,living-room,nouba,séjour,salle,sauterie', 'bal banneton boudoir boutique bringue cabinet cercle club demeure entourage exposition fiesta galerie hall living living-room musée nouba pièce piaule raout ...'),
(49, 1, 1, 'Bureaux', '<div class=\"cell-title\">\n<h2>UN MEUBLE DE BUREAU SUR TRÉTEAU, VOILÀ QUI EST TENDANCE !</h2>\n</div>\n<p> </p>\n<p>Vous manquez d’inspiration pour cette pièce ? Notre gamme complète dédiée au mobilier de bureau va vous aider.L’espace est une chose importante, c’est le seul moyen de retrouver vos papiers efficacement. Pour commencer le tri, ce caisson à tiroir est parfait. Voyez les choses en grand pour le bureau, imaginez-le sur tréteau doté d’un immense plateau de verre. L’idée vous plaît ? C’est ici que ça se passe.Il ne vous reste plus qu’à choisir votre siège de bureau et vous être prêt(e).</p>', NULL, 'bureaux', 'bureau - L\'art du meuble rades', 'comptoir,écritoire,comptoir,direction,directoire,guichet,secrétaire,réunion, secrétariat,table,table reunion,bureau reunion,bureau direction,bureau ecolier,bureautique ', 'comptoir écritoire comptoir direction directoire guichet secrétaire réunion secrétariat table '),
(50, 1, 1, 'Tables', '<p>L\'art du Meuble vous permettent de personnaliser vos mobiliers! Rendez votre mobilier de salon unique en optant pour le tissu ou la couleur de cuir qui vous convient et qui s’harmonisera avec votre décor! Ou encore, choisissez le style de pattes et la couleur de votre prochain mobilier de salle à manger! Pour des créations des et d’ailleurs, venez chez l\'art du meuble! Vous offrir la liberté de choisir, c’est notre spécialité L\'art du meuble rades.</p>', NULL, 'tables', 'table - l\'art du meuble rades', 'l\'art du meuble rades,table ,table basse,table massif,table de décoration ,table de salon,table rand ,table rectangulaire ,table carre ,table de cuisine ,table enfant,table de bureau', 'table - table basse - table massif - table de décoration - décoration - bois  - table de salon - table salon - table rand - table rectangulaire  - table carr...'),
(51, 1, 1, 'Chaises', '<p>Avec ses nombreuses caractéristiques, la chaise de travail est conçue pour les espaces de travail d\'aujourd\'hui. Fabriquée en tenant compte de l\'ergonomie, cette chaise offre de nombreuses caractéristiques ajustables pour plus de confort. </p>', NULL, 'chaises', 'chaise - l\'art du meuble rades', 'chaise,chaise plastique ,chaise cuisine ,chaise attente ,chaise direction,chaise directeur,chaise cuir,chaise architecte ,chaise secrétaire ,chaise enfant ,chaise cuisine ,chaise jardin ,chaise interieur,chaise exterieur,tabouret', 'chaise - tabouret - brancard - brouette - canapé - caquetoire - chauffeuse - coche fauteuil - palanquin relax rocking-chair selle siège trône transatlantique'),
(52, 1, 1, 'Eléments de rangement', '<p>Pour l’aménagement du bureau, Monsieurbureau propose une sélection de<strong> meuble rangement bureau </strong>pour répondre à tous vos besoins<strong>: </strong>solidité<strong> </strong>de l’armoire métallique, chaleur de l’armoire de bureau bois, fonctionnalité de l’armoire dossiers suspendus.  Mais aussi le <strong>meuble rangement bureau</strong> complémentaire du bureau: caisson bureau, caisson mobile ou hauteur bureau. Le <strong>meuble rangement bureau </strong>utile pour les dossiers de grandes tailles: le meuble à clapets. En complément du <strong>meuble rangement bureau</strong> classique, le vestiaire multicases et industries propres ou industries salissantes. N\'hésitez par à consulter la rubrique siège de bureau pour compléter votre aménagement.</p>', NULL, 'elements-de-rangement', 'rangement - l\'art du meuble rades', 'alignement,archivage,arrangement,assemblage,classement,v,distribution,ordonnance,ordre,organisation,placement,element de rangement ,porte chaussure,armoire ,argentiere', 'alignement archivage arrangement assemblage classement distribution ordonnance ordre organisation placement'),
(53, 1, 1, 'Meuble de Jardin', '<p>Profiter notre mobilier et meuble jardin en Tunisie pas cher, table jardin, chaise jardin, salon jardin bas prix.</p>', '', 'meuble-de-jardin', 'Mobilier de Jardin - Salons et tables ext??rieur Tunisie', '', 'meuble jardin en Tunisie pas cher, table jardin, chaise jardin, salon jardin bas prix'),
(54, 1, 1, 'Eléments de cuisine', '<div class=\"cell-title\">\n<h2>LE MEUBLE DE CUISINE POUR UN ESPACE FONCTIONNEL ET FACILE À VIVRE !</h2>\n</div>\n<p>Créer la cuisine de ses rêves, c\'est facile ! Associez caisson de cuisine, casserolier, armoires pour four et meuble haut de cuisine pour transformer cet espace en un lieu pratique et chaleureux. Aménagez un coin repas accueillant avec table, chaises ou tabourets adaptés à votre intérieur. Rangez votre vaisselle grâce à nos aménagements intérieurs et choisissez un évier et un mitigeur à votre goût. Pour trouver l\'inspiration, découvrez notre gamme de meubles de cuisine dans nos idées déco pour la cuisine !</p>', NULL, 'elements-de-cuisine', 'El??ments de cuisine - Meubles de cuisine Tunisie', 'element cuisine,cuisine,rangement cuisine', 'D??couvrez nos ??l??ments de cuisine : caissons, plans de travail, fa??ades. L\'art du meuble Rad??s, fabrication et vente de meubles en Tunisie.'),
(55, 1, 1, 'Séjour Banquet ', '<div class=\"cell-title\">\n<h2>LE CANAPÉ, INDISPENSABLE POUR CRÉER UNE AMBIANCE CONVIVIALE ET CHALEUREUSE</h2>\n</div>\n<p>Quelle que soit la configuration de votre salon, il existe un modèle de canapé fait pour vous ! À choisir en version 2 places pour les petits appartements, convertible pour recevoir les amis ou en angle pour créer un espace détente XXL. Côté matière, vous avez l\'embarras du choix : cuir vachette, croûte de cuir, microfibre, traité anti-tâches ou coton... Et pour adapter votre salon à vos envies, adoptez sans hésiter un canapé modulable design ou sur mesure. Découvrez notre gamme de canapés et nos idées pour aménager votre espace détente !</p>', NULL, 'sejour-banquet', 'banquette - l\'art du meuble rades', 'appui,aqueduc,banc,bas-côté,bord,palissade,parapet,plate-forme,pouf ,siège,sofa,stalle', 'appui aqueduc banc bas-côté bord levée palissade parapet plate-forme pouf siège sofa stalle'),
(56, 1, 1, 'Séjour Coin', '<div class=\"cell-title\">\n<h2>LE CANAPÉ, INDISPENSABLE POUR CRÉER UNE AMBIANCE CONVIVIALE ET CHALEUREUSE</h2>\n</div>\n<p>Quelle que soit la configuration de votre salon, il existe un modèle de canapé fait pour vous ! À choisir en version 2 places pour les petits appartements, convertible pour recevoir les amis ou en angle pour créer un espace détente XXL. Côté matière, vous avez l\'embarras du choix : cuir vachette, croûte de cuir, microfibre, traité anti-tâches ou coton... Et pour adapter votre salon à vos envies, adoptez sans hésiter un canapé modulable design ou sur mesure. Découvrez notre gamme de canapés et nos idées pour aménager votre espace détente !</p>', NULL, 'sejour-coin', 'séjour - l\'art du meuble rades ', 'appui,aqueduc,banc,bas-côté,bord,levée,séjour,palissade,parapet,plate-forme,pouf,siège,sofa,stalle,salle,salon,séjour coin ,salon coin', 'appui aqueduc banc bas-côté bord levée palissade parapet plate-forme pouf siège sofa stalle'),
(57, 1, 1, 'Table Basse', '<p>Conviviale et très pratique, la table basse devient un meuble incontournable dans tous les styles d\'intérieur. Située au cœur du salon, les tables basses ont un rôle précieux au quotidien : vous donner accès à tout ce dont vous avez besoin (télécommande, magazines, boissons, …) tout en restant confortablement assis dans votre canapé.</p>', NULL, 'table-basse', 'table - l\'art du meuble rades', 'table,table basse ,table massif,table de decoration,décoration ,bois ,table de salon,table salon,table rande,table rectangulaire ,table carrée,l\'art du meuble rades', 'table - table basse - table massif - table de décoration - décoration - bois  - table de salon - table salon - table rand - table rectangulaire  - table carrée '),
(58, 1, 1, 'Bureau Ecolier', '<p>Découvrez ces superbe bureaux de style colonial. Élégant et gracieux, il offre un très bel espace de travail, aéré et confortable. Profitez de ces meubles en bois et MDF et passez des journées plus agréables.</p>', NULL, 'bureau-ecolier', 'bureau ecolier - L\'art du meuble rades ', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - bureau écolier - bureautique', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - ...'),
(59, 1, 1, 'Bureau Opérateur', '<p>Découvrez ces superbe bureaux de style colonial. Élégant et gracieux, il offre un très bel espace de travail, aéré et confortable. Profitez de ces meubles en bois et MDF et passez des journées plus agréables.</p>', NULL, 'bureau-operateur', 'bureau opérateur - l\'art du meuble rades ', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - bureau écolier - bureautique ,l\'art du meuble rades', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - ...'),
(60, 1, 1, 'Bureau Direction', '<p>Découvrez ces superbe bureaux de style colonial. Élégant et gracieux, il offre un très bel espace de travail, aéré et confortable. Profitez de ces meubles en bois et MDF et passez des journées plus agréables.</p>', NULL, 'bureau-direction', 'bureau directeur - l\'art du meuble rades', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - bureau écolier - bureautique ,l\'art du meuble rades', 'comptoir - écritoire - direction - directoire - guichet - secrétaire - réunion - secrétariat - table - table - réunion - bureau réunion - bureau direction - ...'),
(61, 1, 1, 'Living', '<div class=\"cell-title\">\n<h2>DANS L’UNIVERS DES ÉTAGÈRES ET BIBLIOTHÈQUES, MIEUX VAUT VOIR LES CHOSES EN GRAND !</h2>\n</div>\n<p>Quel que soit votre style, nous avons la bibliothèque d’angle qu’il vous faut ! Pour y poser le téléphone, la box internet, les dossiers à garder à portée de main et même de beaux objets de décoration, rien de plus pratique et design qu’une bibliothèque, voire une étagère. Ces meubles, peu gourmands en espace, offrent une belle capacité de rangement. Cette étagère d’angle fera le lien entre deux bibliothèques qui ne formeront plus qu’une seule bibliothèque d’angle. Effet de perspective garanti !</p>', NULL, 'living', 'living - l\'art du meuble rades', 'archives,armoire,étagère,bibliobus,bureau,casier,collection,kiosque,meuble,rayonnage', 'archives armoire étagère bibliobus bureau cabinet casier collection kiosque meuble rayonnage'),
(62, 1, 1, 'Table TV', '<p>Passez en revue nos meubles TV, et choisissez celui qui se mariera le mieux à votre intérieur. Il est question de choisir un meuble qui offre du rangement et qui mette votre TV en valeur. Et comme il doit aussi s’accorder à votre intérieur, nous vous proposons une gamme riche de meubles télé.</p>', NULL, 'table-tv', 'Table TV  - l\'art du meuble rades', 'Table,Table Tv,rangement,rangement TV, TV', 'Table Table Tv living rangement TV '),
(63, 1, 1, 'Table Basse', '<p>Conviviale et très pratique, la table basse devient un meuble incontournable dans tous les styles d\'intérieur. Située au cœur du salon, les tables basses ont un rôle précieux au quotidien : vous donner accès à tout ce dont vous avez besoin (télécommande, magazines, boissons, …) tout en restant confortablement assis dans votre canapé.</p>\n<h2 class=\"md_h2_category\">Une table basse pour meubler son salon</h2>\n<p>La table basse est l\'élément central de votre salon. Par conséquent, il est important qu’elle soit accordée à votre pièce et, notamment, au canapé. Le plus important est de choisir le modèle qui correspond le mieux à l’utilisation souhaitée mais également à votre pièce. Par exemple, pour les petits espaces, il est préférable d’opter pour une table basse avec plateau relevable ou qui dispose d’un espace de rangement. Ce choix vous permettra de gagner de la place en ayant un meuble double usage. Autre point important, il est vital de de choisir un modèle qui correspond à votre décoration intérieure.</p>', NULL, 'table-basse', 'table basse - l\'art du meuble rades', 'l\'art du meuble rades,table ,table basse,table massif,table de decoration,table de salon,table rond ,table rectangulaire ,table carre', 'table - table basse - table massif - table de décoration - décoration - bois  - table de salon - table salon - table rand - table rectangulaire  - table carr...'),
(64, 1, 1, 'Table Cuisine', '<p>La table de cuisine est l’élément central de cette pièce de vie. Il en existe un large éventail de styles très différents les uns des autres. Vous trouverez à coup sûr celle qui saura habiller votre cuisine tout en la mettant en valeur !</p>\n<h2 class=\"md_h2_category\">Des tables de cuisine pratiques</h2>\n<p>Au quotidien, la cuisine est généralement l’endroit de partage de la maison. Un petit-déjeuner aux douceurs délectées à deux sur une table de cuisine pliante ou un repas sur le pouce en solo, notre sélection 4 Pieds dispose d’un large choix de tables qui auront la faculté de correspondre à vos attentes. Si vous bénéficiez d’une petite cuisine, nous vous conseillons d’opter pour des tables de cuisine pliables afin de pouvoir la ranger lorsque vous ne l’utilisez pas. Une grande pièce vous permettra de pouvoir accueillir toute votre petite famille ainsi que vos amis pour partager des repas conviviaux autour d’une table de cuisine extensible. Certains modèles disposent même de tiroirs de rangement afin de vous faire gagner de la place ! Il est important que celle que vous choisirez soit pratique et robuste. Utilisée quotidiennement, la table de cuisine se doit d’être résistante. Faites votre choix parmi notre large sélection, vous y trouverez de manière certaine le produit dont vous rêver pour votre cuisine !</p>', NULL, 'table-cuisine', 'table - table de jardain - table cuisine - l\'art du meuble rades', 'table ,table cuisine ,table rond ,table carre,table rectangulaire,table pvc,table verre,table epoxi,l\'art du meuble rades', 'table - table de décoration - décoration - bois - table de salon - table salon - table rand - table rectangulaire  - table carrée  -  table cuisine - table e...'),
(65, 1, 1, 'Table Réunion', '<p>La table de réunion peut avoir de multiple formes et de multiples usages. Simple table de réunion dans le style table de collectivité ou table pliante pratique pour le gain de place, elle est de petite taille et non encombrante. Pour les grandes salles de réunion, vous porterez votre choix sur une grande table de réunion ovale ou rectangulaire. Pour une atmosphère plus conviviale vous opterez pour la table de réunion ronde. Afin de compléter l’assortiment de votre table de réunion, choisissez le siège de bureau adéquat.</p>', NULL, 'table-reunion', 'table réunion -l\'art du meuble rades', 'table réunion ,table ,reunion,réunion ', 'table réunion - table centre d\'appel - centre call '),
(66, 1, 1, 'Table Ecolier - Enfant', '<p>Lart du bureau propose une rubrique bureau modulaire qui montre différentes compositions de bureaux : bureau droit, bureau avec retour, bureau compact, bureau vague, bureau bench. Un bureau modulaire se doit d’être fonctionnel et esthétique. C’est pourquoi en plus des nombreuses combinaison chaque bureau modulaire est présenté dans des formes et coloris différents. Bureau modulaire couleur blanc, gris, aulne, frêne noir, hêtre…Les piètements de chaque bureau modulaire proposent aussi un large choix de forme et de coloris.</p>', NULL, 'table-ecolier-enfant', 'table écolier - l\'art du meuble rades ', 'table,table écolier ,table jardin d\'enfant', 'table - table écolier - petite table - table jardin d\'enfant '),
(67, 1, 1, 'Chaise Cuisine et Jardin', '<p>La cuisine est la pièce la plus conviviale de la maison. Tout le monde s’y retrouve le soir ou le weekend pour partager de bons moments en famille. Afin de rendre la pièce plus pratique et agréable, il est indispensable de choisir avec soin vos meubles, notamment les chaises qui ont tendance à prendre de la place. Plusieurs critères sont à prendre en compte afin de trouver les chaises de cuisine idéales.</p>', '', 'chaise-cuisine-et-jardin', 'Chaise Cuisine et Jardin - l\'art du meuble rades', 'chaise ,chaise plastique,chaise PVC ,chaise ipoxi,chaise interieur ,chaise extérieur ,chaise cuir,chaise cuisine ,chaise jardin ,tabouret,chaise contemporain ,chaise moderne ,chaise classic', 'chaise de cuisine et de jardin contemporain'),
(68, 1, 1, 'Tabouret', '<p>Lointain est le temps où le tabouret était le parent pauvre du meuble de maison. Souvent caché dans les coins reculés des pièces, ou dissimulé sous les tables, il était considéré uniquement comme un siège d’appoint. Désormais, remis à la mode, il occupe une place importante dans tous les intérieurs contemporains et modernes. Décliné sous toutes les formes, et dans toutes les tailles, le tabouret participe dorénavant pleinement à la décoration d’une pièce.</p>', NULL, 'tabouret', 'tabouret - l\'art du meuble rades', 'tabouret,tabouret moderne ,tabouret chic ,tabouret contemporain ,tabouret haut ,tabouret cuir,tabouret plastique  ,tabouret café ,tabouret restaurant ,tabouret ipoxi', 'tabouret  pour les professionnels et les particuliers très confortable et chic  '),
(69, 1, 1, 'Chaise Opérateur', '<p>Lart du Meuble propose un large choix de sièges de bureau. En cuir, en tissu, pivotant, avec ou sans accoudoirs pour un usage professionnel ou personnel … Notre large gamme vous permettra de trouver la chaise de bureau ou le fauteuil bureau le plus à même de correspondre à vos besoins.</p>', NULL, 'chaise-operateur', 'Chaise Opérateur - l\'art du meuble rades', 'chaise opérateur ,chaise secrétaire ,chaise adulte,chaise avec roue ,chaise pivotant ,chaise enfant ,chaise direction,chaise bureautique ,chaise de bureau', 'chaise opérateur - chaise secrétaire - chaise adulte - chaise contemporain - chaise robuste   '),
(70, 1, 1, 'Chaise Directeur', '<p>L art du meuble propose un large choix de sièges de bureau. En cuir, en tissu, pivotant, avec ou sans accoudoirs pour un usage professionnel ou personnel … Notre large gamme vous permettra de trouver la chaise de bureau ou le fauteuil bureau le plus à même de correspondre à vos besoins.</p>', NULL, 'chaise-directeur', 'Chaise Directeur', 'chaise direction,chaise directeur,chaise cuir,chaise haute gamme,chaise contemporain ,chaise relaxant ,chaise orthopédique ,chaise moderne,chaise directionnel ,chaire rabattable', 'Chaise Directeur - chaise haute gamme - chaise contemporain - chaise bureautique '),
(71, 1, 1, 'Chaise Visiteur', '<p>Lart du Meuble propose un large choix de sièges de bureau. En cuir, en tissu, pivotant, avec ou sans accoudoirs pour un usage professionnel ou personnel … Notre large gamme vous permettra de trouver la chaise de bureau ou le fauteuil bureau le plus à même de correspondre à vos besoins.</p>', NULL, 'chaise-visiteur', 'Chaise Visiteur', 'Chaise Visiteur,moderne ,chaise attente,chaise chic,chaise contemporain ,chaise salle d\'attente', 'Chaise Visiteur très chic et très moderne'),
(72, 1, 1, 'Armoire', '<p>Une <strong>armoire</strong> (de <em>Armarium, Armariolus, Armariolum</em>) est un <a title=\"Meuble\" href=\"https://fr.wikipedia.org/wiki/Meuble\">meuble</a> fermé, généralement en <a title=\"Bois\" href=\"https://fr.wikipedia.org/wiki/Bois\">bois</a>, toujours adossé à un mur, que l\'on trouve dans une habitation. Il est destiné à ranger des objets (l\'armoire ferme à clé), spécialement les <a title=\"Vêtement\" href=\"https://fr.wikipedia.org/wiki/V%C3%AAtement\">vêtements</a> et le <a title=\"Linge de maison\" href=\"https://fr.wikipedia.org/wiki/Linge_de_maison\">linge de maison</a>. L\'armoire est une évolution du coffre mobile de la fin du Moyen Âge, en se différenciant du bahut à deux vantaux qui s\'est métamorphosé en armoire ou en buffet, selon qu\'il était horizontal ou vertical.</p>\n<p>L\'armoire est généralement haute, formée d\'un seul corps et munie de portes dits « <a class=\"mw-redirect\" title=\"Vantaux\" href=\"https://fr.wikipedia.org/wiki/Vantaux\">vantaux</a> » (deux en général), d\'étagères de rangement et souvent de penderies. Elle est fréquemement surmontée d\'une <a title=\"Corniche\" href=\"https://fr.wikipedia.org/wiki/Corniche\">corniche</a>. On la trouve surtout dans la <a title=\"Chambre à coucher\" href=\"https://fr.wikipedia.org/wiki/Chambre_%C3%A0_coucher\">chambre à coucher</a>. Ses portes peuvent être munies de <a title=\"Miroir\" href=\"https://fr.wikipedia.org/wiki/Miroir\">miroirs</a>, auquel cas on parle d\'armoire à glace.</p>', NULL, 'armoire', 'Armoires et rangements - L\'art du meuble Rad??s', NULL, 'Armoires 2 portes, portes coulissantes, armoires stratifi??es. Large choix de solutions de rangement - L\'art du meuble Rad??s Tunisie.'),
(74, 1, 1, 'Bibliothèque', '<p>La bibliothèque est un meuble destiné à contenir les livres et volumes. Elle se compose d\'un ou plusieurs corps contenant des étagères ou tablettes.<br />Le corps inférieur est généralement fermé par des portes pleines alors que celui du dessus est vitré ou grillagé. Son bâti est construit de manière robuste pour soutenir le poids des ouvrages et généralement en bois dur et peu sensible aux insectes nuisibles.<br />La bibliothèque ordinaire est d\'assez grande dimension. La bibliothèque de dame, plus petite, ressemble à une étagère fermée à deux portes vitrées ou grillagées.</p>', NULL, 'bibliotheque', 'Bibliothèque - l\'art du meuble rades', 'bibliothèque ,living,rangement,argentier ', 'Bibliothèque contemporain et moderne '),
(75, 1, 1, 'Porte manteau', '<div class=\"wdatabloc\">\n<div class=\"wdatabloccontentitem dtb_maintxt\"><span class=\"txt\">Le porte manteau est un meuble de vestibule servant à accrocher les manteaux, vestes et gilets.<br />Il peut prendre la forme d\'une simple planche munie de crochets ou de patères. Le porte-manteaux perroquet repose sur un long mât terminé par de beaux crochets courbés tout autour.</span></div>\n</div>\n<div class=\"spacer\"> </div>\n<div class=\"wdatabloc\"> </div>', NULL, 'porte-manteau', 'porte manteau - arc-boutant - bossoir - patère - l\'art du meuble rades', 'porte manteau - arc-boutant - bossoir - patère - l\'art du meuble rades', 'porte manteau - arc-boutant - bossoir - patère - l\'art du meuble rades'),
(76, 1, 1, 'Salles à Manger', '<p>l\'art du meuble vous permettent de personnaliser vos mobiliers! Rendez votre mobilier de salon unique en optant pour le tissu ou la couleur de cuir qui vous convient et qui s’harmonisera avec votre décor! Ou encore, choisissez le style de pattes et la couleur de votre prochain mobilier de salle à manger! Pour des créations des sfaxien et d’ailleurs, venez chez l\'art du meuble Vous offrir la liberté de choisir.</p>', NULL, 'salles-a-manger', 'salle a manger - l\'art du meuble rades', 'salle a manger,buffet,chaise,rangement ,table,bibliothèque ,vitrine ,miroir ,console ,decoration,décoration', 'salle a manger - buffet - chaise - rangement  - table - bibliothèque  - vitrine  - miroir  - console  -  décoration '),
(77, 1, 1, 'Call center', '<p>Le call center ou mobilier de centre d\'appel permet de créer une isolation phonique et visuelle pour le confort du visiteur et du salarié. Monsieurbureau a sélectionné chaque call center ou mobilier de centre d\'appel pour son excellent rapport qualité prix. Chaque call center ou mobilier de centre d\'appel s\'adapte à différentes configurations ou environnement dans un soucis d\'économie budgétaire. N\'hésitez pas à choisir un siège de bureau dans la rubrique sièges de bureau pour finaliser l\'aménagement de votre call center.</p>', NULL, 'call-center', 'Mobilier Call Center - Bureaux et postes de travail', 'call-center,centre d\'appelle,table centre d\'appelle,image call centre', 'call-center centre d\'appelle ');
