(74, 1, 1, '<p>Porte Manteau structure métallique fonte    </p>\n<p>Produit importation  </p>\n<p>Couleur : Noir  </p>\n<p>Structure très solide </p>', '<p>Porte Manteau structure métallique fonte    </p>\n<p>Produit importation  </p>\n<p>Couleur : Noir  </p>\n<p>Structure très solide </p>', 'porte-manteaux-structure-metallique', 'Porte Manteau structure métallique fonte      Produit importation    Couleur : Noir    Structure très solide ', NULL, 'Porte manteau - rangement - porte vêtement - l\'art du meuble rades ', 'Porte Manteaux structure métallique ', NULL, NULL, NULL, NULL),
(75, 1, 1, '<div class=\"products-page-cats\">\r\n<div class=\"product-title\">MATELAS DIAMANT</div>\r\n<div class=\"product-excerpt\">\r\n<div class=\"mCSB_container mCS_no_scrollbar\">Carcasse en ressorts biconiques type Bonell en fil d’acier Ø 2,2 mm, reliés par des spires en fil d’acier Ø 1,3 mm pour offrir un soutien ferme. Renforcements des cotés latéraux et des 2 faces de la carcasse par des Plaques de Feutre et par des Plaques et Cadres en Mousse polyéther de densité moyenne pour apporter la durabilité et l’anti-affaissement. Garnissage nappe face hiver en ouate polyester et mousse polyéther de densité moyenne pour un accueil doux et agréable. Garnissage nappe face été en ouate coton et mousse polyéther de densité moyenne pour un accueil doux et agréable. Tissu Jacquard. Aérateur de chaque côté a fin de garantir le recyclage de l’air à l’intérieur du matelas. Housse d’emballage en plastique.</div>\r\n</div>\r\n</div>', '<div class=\"products-page-cats\">Confortex</div>\r\n<div class=\"products-page-cats\">\r\n<p>190*80:250dt</p>\r\n<p>190*90:275dt</p>\r\n<p>190*110:330dt</p>\r\n<p>190*120:340dt</p>\r\n<p>190*100:315dt</p>\r\n<p>200*100:340dt</p>\r\n<p>200*120:400dt</p>\r\n<p>190*140:400dt</p>\r\n<p>200*140:490dt</p>\r\n<p>190*150:485dt</p>\r\n<p>190*160:440dt</p>\r\n<p>200*160:460dt</p>\r\n<p>200*180:530dt</p>\r\n</div>', 'confortex-diament-confortex', 'MATELAS sommier - confortex', '', 'Matelas - Sommier - Lit - couchette - l\'art du meuble rades', 'CONFORTEX DIAMENT CONFORTEX', '', '', '', ''),
(76, 1, 1, '<div class=\"product-title\">Carcasse en ressorts biconiques type Bonell en fil d’acier Ø 2,2 mm, reliés par des spires en fil d’acier Ø 1,3 mm pour offrir un soutien ferme. Renforcements des côtés latéraux et des 2 faces de la carcasse par des Plaques de Feutre et par des Plaques et Cadres en Mousse polyéther de haute densité pour apporter la durabilité et l’anti-affaissement. Garnissage nappe face hiver en ouate polyester et mousse polyéther de haute densité pour un accueil doux et agréable. Garnissage nappe face été en ouate coton et mousse polyéther de haute densité pour un accueil doux et agréable. Tissu Stretch donnant une touché très doux. Aérateur de chaque côté à fin de garantir le recyclage de l’air à l’intérieur du matelas. Capitonnage intérieur invisible pour une meilleure stabilité du matelas. Traitement Anti Acarien. Housse d’emballage en plastique.</div>', '<div class=\"product-title\">MATELAS ORTHOPEDIQUE (5 ans de garantit)</div>\n<div class=\"product-title\"> </div>\n<div class=\"product-excerpt\">\n<div class=\"mCSB_container mCS_no_scrollbar\">\n<div class=\"products-page-cats\"> </div>\n<div class=\"products-page-cats\">\n<div class=\"products-page-cats\">\n<div class=\"products-page-cats\"> </div>\n<div class=\"products-page-cats\">\n<p>190*80:310dt</p>\n<p>190*90:350dt</p>\n<p>190*110:425dt</p>\n<p>190*120:460dt</p>\n<p>190*100:405dt</p>\n<p>200*100:420dt</p>\n<p>200*120:515dt</p>\n<p>190*140:515dt</p>\n<p>200*140:610dt</p>\n<p>190*150:610dt</p>\n<p>190*160:550dt</p>\n<p>200*160:600dt</p>\n<p>200*180:690dt</p>\n</div>\n</div>\n</div>\n</div>\n</div>', 'confortex-orthopedique-5-ans-de-garanties', 'CONFORTEX Orthopédique 5 ans de garanties ', NULL, 'Matelas - Sommier - couchette - CONFORTEX Orthopédique  ', 'CONFORTEX Orthopédique 5 ans de garanties ', NULL, NULL, NULL, NULL),
(78, 1, 1, '<div class=\"bullet_title mb-2\">Technologique</div>\n<div class=\"bullet_descr\">Avec cette chaise de bureau, une nouvelle ère s\'ouvre. Cette chaise de bureau haute technologie vous permettra de vous sentir léger comme une plume, même après une longue journée de travail, vous vous sentirez bien et en forme chaque jour. À noter la grande qualité et la résistance du filet respirant à 100 %, parfait pour tous les types d\'environnements.</div>', '<strong>Chaise pour Ordinateur Tesla, en maille, avec appui-tête et soutien lombaire </strong>\n<ul><li>Mousse Haute densité</li>\n<li>Régler la hauteur du siège</li>\n<li>Régler l\'appui lombaire (support lombaire)</li>\n<li>Régler la tension du dossier</li>\n</ul>', 'chaise-direction-tesla', 'Mousse Haute densité Régler la hauteur du siège Régler l\'appui lombaire Régler la tension du dossier', NULL, 'Chaise tesla chaise ergonomique ', 'Chaise Direction Tesla', NULL, NULL, NULL, NULL),
