(154, 1, 1, '<p>CHAISE CONFORT BOSTON est un fauteuil de bureau tout confort : mécanisme synchrone, têtière réglable, dossier filet avec un cousin lombaire et des accoudoirs réglables .</p>', '<p>CHAISE CONFORT BOSTON est un fauteuil de bureau tout confort : mécanisme synchrone, têtière réglable, dossier filet avec un cousin lombaire et des accoudoirs réglables .</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-boston', 'CHAISE CONFORT BOSTON est un fauteuil de bureau tout confort : mécanisme synchrone, têtière réglable, dossier filet avec un cousin lombaire et des accoudoi.....', NULL, 'Chaise - bureautique - assise - bureau - l\'art du meuble rades', 'CHAISE BOSTON', NULL, NULL, NULL, NULL),
