(159, 1, 1, '<p>Zodiac est une Chaise réglable en hauteur<br />conçu essentiellement pour des personnes<br />à petit gabarit ,bref c\'est une chaise à petit budget.<br /><strong>Couleur :</strong> Toutes les Couleurs.</p>', '<p>Zodiac est une Chaise réglable en hauteur<br />conçu essentiellement pour des personnes<br />à petit gabarit ,bref c\'est une chaise à petit budget.<br /><strong>Couleur :</strong> Toutes les Couleurs.</p>', 'chaise-zodiac', 'Zodiac est une Chaise réglable en hauteur conçu essentiellement pour des personnes à petit gabarit ,bref c\'est une chaise à petit budget.', NULL, 'chaise - direction- bureautique - écolier - l\'art du meuble rades', 'Chaise Zodiac', NULL, NULL, NULL, NULL),
