(166, 1, 1, '<div class=\"co8aDb\">\n<div class=\"co8aDb\"><strong>Liste des <strong>couleurs</strong></strong></div>\n<div class=\"RqBzHd\">\n<ul class=\"i8Z77e\"><li class=\"TrT0Xe\">BLEU.</li>\n<li class=\"TrT0Xe\">ROSE.</li>\n<li class=\"TrT0Xe\">ROUGE.</li>\n<li class=\"TrT0Xe\">ORANGE.</li>\n<li class=\"TrT0Xe\">JAUNE.</li>\n<li class=\"TrT0Xe\">VERT. NOIR. MARRON. GREGE. BLANC.</li>\n</ul></div>\n</div>', '<p>Sigma </p>\n<p>Produit importation </p>\n<p>Grand classique du mobilier de bureau, le siège se décline en 2 modèles selon l\'utilisation, rembourré comme siège visiteur et de réunion et avec un accoudoir et une tablette écritoire pour l\'enseignement.</p>', 'chaise-sigma', 'La chaise est un grand classique par sa polyvalence et ses qualBasculer vers l\'éditeur de texte brutités : empilable, indémodable, robuste...', NULL, 'chaise - attente - bureautique - écolier - l\'art du meuble rades', 'Chaise  Sigma', NULL, NULL, NULL, NULL),
(168, 1, 1, '<p>TABLE ENFANT<br />Structure en acier peinture<br />epoxy et plateau en<br />stratifié</p>\n<p> </p>', '<p>TABLE ENFANT<br />Structure en acier peinture<br />epoxy et plateau en<br />stratifié</p>\n<p>Dimensions:</p>\n<p>L60L60  H60 : 110 dt</p>\n<p>L90L60 H52 : 125 dt</p>\n<p>L120L60 H60 : 146 dt</p>\n<p>diametre 120cm H60 : 250 dt</p>\n<p>CHAISE ENFANT<br />Assise et dossier en stratifie<br />et socle en acier peinture<br />epoxy</p>\n<p>Prix 39 dt</p>', 'table-enfant', 'Table ENFANT Assise et dossier en stratifie et socle en acier peinture epoxy', NULL, 'chaise - attente - bureautique - écolier - l\'art du meuble rades', 'Table enfant', NULL, NULL, NULL, NULL),
(169, 1, 1, '<h2>Elément Demi - Porte Vitrée</h2>\n<div class=\"extrait\">Rangement de dossiers . Dimensions : 185 * 90 * 45</div>\n<div class=\"extrait\">Rangez jusqu’à 110 Kg par étagère et bénéficiez des nombreux accessoires organisateurs : dossiers suspendus extractibles, séparateurs, bacs, tablettes télescopiques.</div>', '<h2>Elément Demi - Porte Vitrée</h2>\n<p>Couleur disponible Blanc - Etre - Noir</p>\n<div class=\"extrait\">Rangement de dossiers . Dimensions : 185 * 90 * 45</div>\n<div class=\"extrait\">Rangez jusqu’à 110 Kg par étagère et bénéficiez des nombreux accessoires organisateurs : dossiers suspendus extractibles, séparateurs, bacs, tablettes télescopiques.</div>', 'element-demi-porte-vitree', 'Rangez 110 Kg par étagère et bénéficiez des nombreux accessoires organisateurs : dossiers suspendus extractibles, séparateurs, bacs, tablettes télescopique.....', NULL, 'rangement - armoire - rayonnage - caisson - l\'art du meuble rades', 'Elément Demi - Porte Vitrée', NULL, NULL, NULL, NULL),
(170, 1, 1, '<strong>Armoire MEL à demi porte</strong>\n<div class=\"print-desc\">EN PANNAEAU STRATIFIE DIM: 180X90X45cm</div>', '<strong>Armoire MEL à demi porte</strong>\n<div class=\"print-desc\">EN PANNAEAU STRATIFIE DIM: 180X90X45cm</div>', 'element-demi-portes-stratifiee', 'Armoire MEL à demi porte EN PANNAEAU STRATIFIE DIM: 180X90X45cm', NULL, 'rangement - armoire - rayonnage - caisson - l\'art du meuble rades', 'Elément Demi Portes Stratifiée', NULL, NULL, NULL, NULL),
