(180, 1, 1, '<p>TABLE FIXE<br />Plateau en isotop avec socle en acier peinture ou chrome </p>\n<p>***peinture***</p>\n<p>ISOTOP Dimensions:</p>\n<p>70*70 :235 dt  / 110*70 :317 dt / 120*70 :317 dt </p>\n<p> </p>\n<p>MEGA Dimensions:</p>\n<p>70*70 :115 dt</p>\n<p> </p>\n<p>***chromé*** </p>\n<p>ISOTOP Dimensions:</p>\n<p>70*70 :261 dt / 110*70 :347 dt / 120*70 :347 dt / </p>\n<p> </p>', '<p>TABLE FIXE<br />Plateau en isotop avec socle en acier peinture ou chrome </p>\n<p>***peinture***</p>\n<p>ISOTOP Dimensions:</p>\n<p>70*70 :235 dt  / 110*70 :317 dt / 120*70 :317 dt </p>\n<p>MEGA Dimensions:</p>\n<p>70*70 :115 dt</p>\n<p>***chromé*** </p>\n<p>ISOTOP Dimensions:</p>\n<p>70*70 :261 dt / 110*70 :347 dt / 120*70 :347 dt </p>\n<p> </p>', 'table-fixe', 'TABLE FIXE Plateau en isotop avec socle en acier peinture ou chrome ', NULL, 'table - table de jardain - table cuisine - l\'art du meuble rades', 'TABLE FIXE', NULL, NULL, NULL, NULL),
(181, 1, 1, '<p>TABLE BISTRO MEGA<br />Table bistro en acier peint epoxy avec plateau en MEGA (Plateau Plastique dur)</p>\n<p>**Socle peinture**</p>\n<p>Hauteur : 75 / diametre 63: 64dt</p>\n<p>Hauteur : 120 / diametre 63 : 76 dt</p>\n<p> </p>\n<p>**Socle Chromé**</p>\n<p>Hauteur : 75 / diametre 63 : 79 dt </p>\n<p>Hauteur : 120 / diametre 63 : 97 dt </p>', '<p>TABLE MEGA<br />Table bistro en acier peint epoxy avec plateau en MEGA (Plateau Plastique dur)</p>\n<p>Ajoutez à votre salle a manger une table  design comme celle que nous vous proposons en bois  et métal industriel récupéré.Cette table basse de style industriel vous permettra de créer une atmosphère chaleureuse et détendue dans votre salle a manger.Vous serez satisfait par sa qualité et sa finition.</p>', 'table-bistro-mega', 'TABLE MEGA Table bistro en acier peint epoxy avec plateau en MEGA (Plateau Plastique dur)', NULL, 'table - table de jardain - table cuisine - l\'art du meuble rades', 'TABLE BISTRO MEGA', NULL, NULL, NULL, NULL),
(182, 1, 1, '<p><strong>Table en acier chromé ou peint avec plateau en polypropylène</strong></p>\n<p> </p>\n<p>TABLE FIXE<br /><br /></p>\n<p>***peinture***</p>\n<p>MEGA Dimensions:</p>\n<p>70*70 :115 dt</p>\n<p> </p>', '<p>Table en acier chromé ou peint avec plateau en polypropylène </p>\n<p>TABLE FIXE <br /><br /></p>\n<p>***peinture***</p>\n<p>MEGA Dimensions:</p>\n<p>70*70 :115 dt</p>\n<p> </p>', 'fixe-mega', 'Table MEGA Plateau Plastique Table en acier chromé ou peint avec plateau en polypropylène', NULL, 'table - table de jardain - table cuisine - l\'art du meuble rades', 'FIXE MEGA', NULL, NULL, NULL, NULL),
(183, 1, 1, '<p>TABLE ISOTOP PVC<br />Table bistro en acier peint epoxy avec plateau en MIDI (ISOTOP)</p>\n<p>**Socle peinture**</p>\n<p>Hauteur : 75</p>\n<p>70*70 : 195 dt  / diametre 60 : 169 dt </p>\n<p>Hauteur : 120 </p>\n<p>70*70 : 213 dt / diametre 60 : 187 dt </p>\n<p>**Socle Chromé**</p>\n<p>Hauteur : 75</p>\n<p>70*70 : 209 dt /diametre 60 : 185 dt </p>\n<p>Hauteur : 120 </p>\n<p>70*70 : 233 dt diametre 60 : 207 dt </p>', '<p> </p>\n<p>Table bistro en acier peint epoxy avec plateau (ISOTOP)</p>\n<p>TABLE ISOTOP PVC<br />Table bistro en acier peint epoxy avec plateau en MIDI (ISOTOP)</p>\n<p>**Socle peinture**</p>\n<p>Hauteur : 75</p>\n<p>70*70 : 195 dt  / diametre 60 : 169 dt </p>\n<p>Hauteur : 120 </p>\n<p>70*70 : 213 dt / diametre 60 : 187 dt </p>\n<p>**Socle Chromé**</p>\n<p>Hauteur : 75</p>\n<p>70*70 : 209 dt /diametre 60 : 185 dt </p>\n<p>Hauteur : 120 </p>\n<p>70*70 : 233 dt diametre 60 : 207 dt </p>', 'table-bistro-isotop', 'TABLE Bistro ISOTOP Table bistro en acier peint epoxy avec plateau en MIDI (ISOTOP PVC)', NULL, 'table - table de jardain - table cuisine - l\'art du meuble rades', 'TABLE Bistro ISOTOP ', NULL, NULL, NULL, NULL),
(195, 1, 1, '<p>Ce portemanteau tout bois se compose d\'une tête rotative avec 4 patères en bois à embouts larges, de 4 crochets en bois ainsi que d\'une large base à 4 pieds. Fût tout bois Ø 42 mm.</p>', '<p>Ce portemanteau tout bois se compose d\'une tête rotative avec 4 patères en bois à embouts larges, de 4 crochets en bois ainsi que d\'une large base à 4 pieds. Fût tout bois Ø 42 mm.#Porte #Monteau En Bois Hêtre..</p>', 'porte-manteau-bois-hetre', 'Ce portemanteau tout bois se compose d\'une tête rotative avec 4 patères en bois à embouts larges, de 4 crochets en bois ainsi que d\'une large base à 4 pied.....', NULL, 'Porte manteau bois Hetre - patere arcboutant', 'Porte manteau bois Hêtre', NULL, NULL, NULL, NULL),
(203, 1, 1, '<p>La chaise de bureau ARCHITECTE a une assise et un dossier haut est composé d\'un revètement Simili cuir vous donnant un confort remarquable. Cette chaise de bureau ARCHITECTE est d\'une grande solidité grâce à son carénage en ABS noir . Cette chaise est réglable en hauteur via un vérin. couleurs: tous les couleurs.</p>', '<p>La chaise de bureau ARCHITECTE a une assise et un dossier haut est composé d\'un revètement Simili cuir vous donnant un confort remarquable. Cette chaise de bureau ARCHITECTE est d\'une grande solidité grâce à son carénage en ABS noir . Cette chaise est réglable en hauteur via un vérin. couleurs: tous les couleurs.</p>', 'chaise-architecte-confort-avec-dos', 'La chaise de bureau ARCHITECTE a une assise et un dossier haut est composé d\'un revêtement Simili cuir vous donnant un confort remarquable. ', NULL, 'Chaise - Tabouret - assise - cuisine - l\'art du meuble rades', 'Chaise Architecte confort avec dos', NULL, NULL, NULL, NULL),
