(301, 1, 1, '<p>CAISSON CUISINE COLONNE</p>\n<div class=\"product-prices\">\n<div class=\"product-discount\">COLONNE DE RANGEMENT couleur disponible : noir ,blanc , rouge vif , rouge bordeaux ,vert pistache ,oranger ,Grège , Chaîne clair et foncer </div>\n</div>\n<div class=\"product-information\">\n<div id=\"product-description-short-86\">\n<p>Dimensions : </p>\n<p> -Largeur : 90 cm </p>\n<p> -Profondeur : 47 cm </p>\n<p> -Hauteur : 190 cm</p>\n</div>\n</div>', '<p>CAISSON CUISINE COLONNE</p>\n<div class=\"product-prices\">\n<div class=\"product-discount\">COLONNE DE RANGEMENT couleur disponible : noir ,blanc , rouge vif , rouge bordeaux ,vert pistache ,oranger ,Grège , Chaîne clair et foncer </div>\n</div>\n<div class=\"product-information\">\n<div id=\"product-description-short-86\">\n<p>Dimensions : </p>\n<p> -Largeur : 90 cm </p>\n<p> -Profondeur : 47 cm </p>\n<p> -Hauteur : 190 cm</p>\n</div>\n</div>', 'caisson-cuisine-colonne', 'élément de rangement,l\'art du meuble Tunisie,l\'art du meuble rades,meuble Tunisie,meuble rades,l\'art du meuble.tn,porte chaussure,meuble et ameublement', NULL, 'élément cuisine - L\'art du meuble Rades - meuble Tunisie - meuble', 'CAISSON CUISINE COLONNE', NULL, NULL, NULL, NULL),
(303, 1, 1, '<div><strong>Porte chaussure ASTRO 3 portes 1 tiroir</strong></div>\n<div><strong>Détails du produit :</strong></div>\n<div>Dimensions en cm (HxLxP) :100x90x40<br />matières : particules stratifiés<br />Couleur façade disponible . Blanc ou Grege</div>', '<div><strong>Porte chaussure ASTRO 3 portes 1 tiroir</strong></div>\n<div><strong>Détails du produit :</strong></div>\n<div>Dimensions en cm (HxLxP) :100x90x40<br />matières : particules stratifiés<br />Couleur façade disponible . Blanc ou Grege</div>', 'astro-3-portes-tiroirs-blanc', 'Porte chaussure ASTRO 3 portes 1 tiroir Blanc : Dimensions en cm (HxLxP) :100x90x40 matières : particules stratifiés Couleur façade disponible . Blanc ou G.....', NULL, 'PC ASTRO 3 Portes Blanc -L\'art du meuble Rades -meuble Tunisie -meuble', 'ASTRO 3 PORTES + TIROIRS Blanc', NULL, NULL, NULL, NULL),
(304, 1, 1, '<h2 class=\"font-weight-normal\">Les options disponibles sur ce modèle de chaise de bureau design en tissu.</h2>\n<p>Goutez au confort d\'une chaise de bureau design synchrone sur lequel vous pourrez aussi reposer votre nuque et vos cervicales grâce à la têtière intégrée réglable en hauteur sur 17 cm fait de cuir synthétique noir. Ce fauteuil de bureau design est idéal pour un bureau individuel ou pour un bureau de direction grâce à son look classe. Ce modèle de chaise de bureau ergonomique design conviendra aussi bien à votre domicile pour les personnes travaillant de longues heures en télétravail.</p>\n<h2 class=\"font-weight-normal\">Les conseils d\'utilisations du fauteuil de bureau design synchrone APPY.</h2>\n<p>Ce fauteuil de bureau design en tissu et filet est aussi idéal pour une utilisation allant jusqu\'à 8 heures par jour par une personne ne dépassant pas les 110 kg. Ce siège de bureau au design classe en polypropylène et tissu dispose d\'accoudoirs réglables en hauteur, profondeur et orientation, vous permettant d\'avoir une position plus agréable.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire</p>', '<p>Fauteuil de bureau design moderne, tapissé de tissu noir avec une mousse épaisse. Goutez au confort d\'un siège de bureau basculant grâce auquel vous pourrez aussi reposer votre nuque grâce à la têtière épaisse confortable, idéale dans les moments de relax</p>', 'fauteuil-de-bureau-appy', 'Chaise Fauteuil de bureau design moderne est une chaise économique basculante réglable en hauteur. Couleur: Noir/rouge/vert/blanc simili-cuir.', NULL, 'Chaise - bureautique - assise - bureau - l\'art du meuble rades', 'Fauteuil de bureau APPY', NULL, NULL, NULL, NULL),
(305, 1, 1, '<h2 class=\"font-weight-normal\">Une assise de bureau personnalisée pour chaque utilisateur</h2>\n<p>Le siège de bureau ergonomique BURGY est équipé d\'une têtière réglable en hauteur et en inclinaison, ainsi que d\'accoudoirs, permettant un ajustement précis et personnalisé. L\'assise, dotée d\'une mousse de 40 mm d\'épaisseur, offre un confort exceptionnel, tandis que le dossier en filet noir assure une ventilation optimale.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire</p>', '<p>Découvrez la chaise de bureau BURGY, alliant confort ergonomique et design moderne. Avec sa têtière réglable, ses accoudoirs et son mécanisme synchrone, elle est idéale pour des journées de travail prolongées. Investissez dans votre bien-être avec cette chaise de bureau haut de gamme</p>', 'burgy-chaise-de-bureau-synchrone-avec-accoudoirs-et-tetiere', 'Chaise MONACO DIRECTEUR  La Chaise MONACO DIRECTEUR est une chaise économique basculante réglable en hauteur. Couleur: Noir/rouge/vert/blanc simili-cuir.', NULL, 'Chaise - bureautique - assise - bureau - l\'art du meuble rades-meuble', 'BURGY - Chaise de Bureau Synchrone avec Accoudoirs et Têtière', NULL, NULL, NULL, NULL),
(306, 1, 1, '<p>Fauteuil agent modèle Sydney Direction  tournant, roulant, basculant, avec accoudoirs et réglable en hauteur</p>\n<ul><li>Structure : en bloc</li>\n</ul><ul><li>Accoudoirs : fixe en acier chromé</li>\n</ul><ul><li>Revêtement : similicuir </li>\n</ul><ul><li>Garnissage assise &amp; dossier : mousse polyuréthane (densité 22kg/m3).</li>\n</ul><ul><li>Piètement (base): métal finition chromée ou PVC nylon selon choix</li>\n</ul><ul><li>Mécanisme : basculant centré simple</li>\n</ul>', '<div> </div>\n<div class=\"c5_fp_desc\">\n<p>Fauteuil agent modèle Sydney Direction  tournant, roulant, basculant, avec accoudoirs et réglable en hauteur</p>\n<ul><li>Accoudoirs : fixe en acier chromé</li>\n</ul><ul><li>Revêtement : similicuir </li>\n</ul><ul><li>Piètement (base): métal finition chromée ou PVC nylon selon choix</li>\n</ul></div>\n<div class=\"c5_fp_desc\"><strong>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire</strong></div>', 'chaise-gm-piccolo', 'Fauteuil agent modèle Sydney Direction  tournant, roulant, basculant, avec accoudoirs et réglable en hauteur', NULL, 'chaise - direction- bureautique - écolier - l\'art du meuble rades ', 'Chaise de direction Sydney', NULL, NULL, NULL, NULL),
(307, 1, 1, '<p>Argentière </p>\n<p>Dimensions L*P*H: 100/ 47/ 200 (cm)</p>\n<p>Coloris aux choix</p>\n<p>Structure Bois Rouge </p>', '<p>Argentière </p>\n<p>Dimensions L*P*H: 100/ 47/ 200 (cm)</p>\n<p>Coloris aux choix</p>\n<p>Structure Bois Rouge </p>', 'argentiere-2-porte-tiroir', 'Argentière L\'art du meuble rades 2 porte + tiroir  Dimensions L*P*H: 100/ 47/ 200 (cm)  Coloris aux choix  Structure Bois Rouge ', NULL, 'Argentière - table - manger - tablette - l\'art du meuble - rangement', 'Argentière 2 Porte + Tiroir ', NULL, NULL, NULL, NULL),
(308, 1, 1, '<div>\n<table class=\"c5_fp_t1\"><tbody><tr><td class=\"c5_fp_t1i\"><span id=\"ctl00_cp1_lb_tit\">Chaise ERGO </span></td>\n</tr></tbody></table></div>\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">Le Brio moyen model est une chaise pivotante,<br />réglable en hauteur à dossier basculant.<br /></span></div>\n<div class=\"c5_fp_desc\"> </div>\n<div class=\"c5_fp_desc\"><strong>Couleur :</strong> tout les couleurs</div>', '<div>\n<table class=\"c5_fp_t1\"><tbody><tr><td class=\"c5_fp_t1i\"><span id=\"ctl00_cp1_lb_tit\">Chaise ERGO </span></td>\n</tr></tbody></table></div>\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">Le Brio moyen model est une chaise pivotante,<br />réglable en hauteur à dossier basculant.<br /></span></div>\n<div class=\"c5_fp_desc\"> </div>\n<div class=\"c5_fp_desc\"><strong>Couleur :</strong> tout les couleurs</div>', 'chaise-ergo-sans-accoudoir', 'Chaise ERGO Sans Accoudoir  Le Brio moyen model est une chaise pivotante, réglable en hauteur à dossier basculant couleur au choix.', NULL, 'chaise bureau - bureautique - direction - l\'art du meuble - chaise', 'Chaise ERGO Sans Accoudoir ', NULL, NULL, NULL, NULL),
(310, 1, 1, '<p>Chaise Jumelée en simili cuir 3 places avec socle chromé</p>', '<p>Chaise Jumelée en simili cuir 3 places avec socle chromé</p>\n<div class=\"co8aDb\"><strong>Liste des <strong>couleurs</strong></strong></div>\n<div class=\"RqBzHd\">\n<ul class=\"i8Z77e\"><li class=\"TrT0Xe\">BLEU.</li>\n<li class=\"TrT0Xe\">VIOLET.</li>\n<li class=\"TrT0Xe\">ROSE.</li>\n<li class=\"TrT0Xe\">ROUGE.</li>\n<li class=\"TrT0Xe\">ORANGE.</li>\n<li class=\"TrT0Xe\">JAUNE.</li>\n<li class=\"TrT0Xe\">VERT. NOIR. MARRON. GRIS. BLANC.</li>\n</ul></div>', 'chaise-jumelee-en-simili-cuir-3-places-avec-socle-chrome', 'Chaise Jumelée en simili cuir 3 places avec socle chromé', NULL, 'Chaise Ergonomique Tunisie - l\'art du meuble - chaise Tunisie - bureau', 'Chaise Jumelée en simili cuir 3 places avec socle chromé', NULL, NULL, NULL, NULL),
