(553, 1, 1, '<p>Assise et dossier : Assise et dossier rembourrés en mousse souple avec couche de dacron.</p>\n<p>Revêtements : Similicuir</p>\n<p>Accoudoirs : Fixe.</p>\n<p>Mécanisme : Mécanisme tournant, roulant, réglable en hauteur et en inclinaison.</p>\n<p>Base ou piétements : Structure étoilée à 05 branches avec 05 roulettes tournantes roulantes à  double galets</p>', '<p> Chaise de Bureau SEDAN HD</p>\n<p>Assise et dossier : Assise et dossier rembourrés en mousse souple avec couche de dacron.</p>\n<p>Revêtements : Similicuir</p>\n<p>Accoudoirs : Fixe.</p>\n<p>Mécanisme : Mécanisme tournant, roulant, réglable en hauteur et en inclinaison.</p>\n<p>Base ou piétements : Structure étoilée à 05 branches avec 05 roulettes tournantes roulantes à  double galets</p>', 'chaise-de-bureau-sedan-hd', ' Chaise de Bureau SEDAN HD  Assise et dossier : Assise et dossier rembourrés Revêtements : Similicuir  Accoudoirs : Fixe. ', NULL, ' Chaise de Bureau SEDAN HD CHAISE TUNISIE CHAISE DIRECTEUR DIRECTION', 'Chaise de Bureau SEDAN HD', NULL, NULL, NULL, NULL),
(554, 1, 1, '<p>Assise et dossier : Assise et dossier rembourrés en mousse souple avec couche de dacron.</p>\n<p>Revêtements : Similicuir</p>\n<p>Accoudoirs : Fixe.</p>\n<p>Mécanisme : Mécanisme tournant, roulant, réglable en hauteur et en inclinaison.</p>\n<p>Base ou piétements : Structure étoilée à 05 branches avec 05 roulettes tournantes roulantes à  double galets</p>', '<p> Chaise de Bureau SEDAN BD</p>\n<p>Assise et dossier : Assise et dossier rembourrés en mousse souple avec couche de dacron.</p>\n<p>Revêtements : Similicuir</p>\n<p>Accoudoirs : Fixe.</p>\n<p>Mécanisme : Mécanisme tournant, roulant, réglable en hauteur et en inclinaison.</p>\n<p>Base ou piétements : Structure étoilée à 05 branches avec 05 roulettes tournantes roulantes à  double galets</p>', 'chaise-de-bureau-sedan-bd', ' Chaise de Bureau SEDAN BD  Assise et dossier : Assise et dossier rembourrés Revêtements : Similicuir  Accoudoirs : Fixe. ', NULL, ' Chaise de Bureau SEDAN HD CHAISE TUNISIE CHAISE DIRECTEUR DIRECTION', 'Chaise de Bureau SEDAN BD', NULL, NULL, NULL, NULL),
(555, 1, 1, '<p>Chaise de Bureau avec un style de conception élégant et simple ergonomique du dossier incurvé est très confortable - Réglable en hauteur et pivotante - Socle chromé - 5 roulettes en nylon - Couleur: Noir </p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>Chaise de Bureau avec un style de conception élégant et simple ergonomique du dossier incurvé est très confortable - Réglable en hauteur et pivotante - Socle chromé - 5 roulettesen nylon - Couleur: Noir </p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-directeur-yaris-mesh', 'Chaise avec un style de conception élégant ergonomique du dossier incurvé est très confortable Réglable en hauteur et pivotante Socle chromé 5 roulettesen .....', NULL, 'CHAISE DIRECTEUR YARIS MESH chaise direction tunisie ergonomique', 'CHAISE DIRECTEUR YARIS MESH', NULL, NULL, NULL, NULL),
(556, 1, 1, '<p>Chaise de Bureau avec un style de conception élégant et simple ergonomique du dossier incurvé est très confortable - Réglable en hauteur et pivotante - Socle chromé - 5 roulettes en nylon - Couleur: Noir </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>Chaise de Bureau avec un style de conception élégant et simple ergonomique du dossier incurvé est très confortable - Réglable en hauteur et pivotante - Socle chromé - 5 roulettes en nylon - Couleur: Noir </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-directeur-york', 'Chaise avec un style élégant et ergonomique du dossier incurvé est très confortable Réglable en hauteur et pivotante Socle chromé 5 roulettes en nylon', NULL, 'CHAISE DIRECTEUR WORK MESH chaise direction tunisie orthopédique', 'CHAISE DIRECTEUR YORK', NULL, NULL, NULL, NULL),
(557, 1, 1, '<strong>TABLE DE RÉUNION OVAL 2000x1000 avec socle mélaminé</strong>\n<p> </p>', '<strong>TABLE DE RÉUNION OVAL 2000x1000 avec socle mélaminé</strong>\n<p> </p>', 'table-de-reunion-oval-2000x1000', 'TABLE DE RÉUNION OVAL 2000x1000 avec socle mélaminé', NULL, 'TABLE DE RÉUNION', 'TABLE DE RÉUNION OVAL 2000x1000', NULL, NULL, NULL, NULL),
(558, 1, 1, '<p>Chaise de bureau distinctif  - une touche supplémentaire à votre bureau - un design à dossier haut avec des coussins ergonomiques rembourrés du dossier avec accoudoir permettent des longues sessions de jeu ou de travail - La conception réglable en hauteur vous permet d’ajuster la hauteur de la chaise et d’obtenir du confort accru- Couleur: Noir / rouge / gris</p>', '<p>Chaise de bureau distinctif  - une touche supplémentaire à votre bureau - un design à dossier haut avec des coussins ergonomiques rembourrés du dossier avec accoudoir permettent des longues sessions de jeu ou de travail - La conception réglable en hauteur vous permet d’ajuster la hauteur de la chaise et d’obtenir du confort accru- Couleur: Noir / rouge / gris</p>\n<p> </p>\n<p> </p>', 'chaise-de-bureau-ariel-mesh', 'Chaise de bureau distinctif  - une touche supplémentaire à votre bureau - un design à dossier haut avec des coussins ergonomiques rembourrés du dossier ave', NULL, 'Chaise de Bureau Ariel Mesh', 'Chaise de Bureau Ariel Mesh', NULL, NULL, NULL, NULL),
(560, 1, 1, '<ul><li>Dos en maille élastique durable avec appui-tête</li>\n<li>Siège en mousse confortable avec tissu coloré</li>\n<li>Mécanisme papillon pour un réglage facile de la hauteur et de l’inclinaison</li>\n<li>Base en nylon durable</li>\n<li>Roulettes robustes en nylon</li>\n</ul>', '<ul><li>Dos en maille élastique durable avec appui-tête</li>\n<li>Siège en mousse confortable avec tissu coloré</li>\n<li>Mécanisme papillon pour un réglage facile de la hauteur et de l’inclinaison</li>\n<li>Base en nylon durable</li>\n<li>Roulettes robustes en nylon</li>\n</ul>', 'chaise-de-bureau-costa-mesh', ' Chaise de Bureau COSTA Mesh chaise direction tunisie ergonomique chaise secretere', NULL, ' Chaise de Bureau COSTA Mesh chaise direction tunisie ergonomique', 'Chaise de Bureau COSTA Mesh', NULL, NULL, NULL, NULL),
