(576, 1, 1, '<p>Dimension table : 183 / 88 cm </p>\n<p>matiere bois BLENZ </p>', '<p>Table a manger </p>\n<p>Bois Blenz</p>\n<p>La table a manger H rayé Bois Blenz est une table aux finitions soignées. Son plateau a une finition au rendu doucement poudré. Les 6 chaises sont surélevées de 4 pieds d’inspiration nordiques.</p>\n<p>Dimension table : 183 / 88 cm </p>\n<p>matiere bois BLENZ </p>', 'table-a-manger-h-raye-bois-blenz', 'Table a manger Gold Bois Blenz  La table a manger scandinave Tunisie Gold. Les 6 chaises sont surélevées de 4 pied. matière bois BLENZ ', NULL, 'Table a manger Gold Bois Blenz  La table a manger scandinave tunisie', 'Table a manger H rayé Bois Blenz', NULL, NULL, NULL, NULL),
(580, 1, 1, '<p>Chaise Salle de Fête confortable HILTON</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Produit disponible en gros seulement </p>', '<p>Chaise Salle de Fête confortable HILTON</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Carcasse en acier</p>\n<p>peinture epoxy couleur au choix</p>\n<p>Produit disponible en gros seulement </p>', 'chaise-salle-de-fete-confortable-hilton', 'Chaise Salle de Fête confortable HILTON Carcasse en acier  peinture epoxy couleur au choix', NULL, 'Chaise Salle de Fête confortable HILTON en acier  peinture epoxy', 'Chaise Salle de Fête confortable HILTON', NULL, NULL, NULL, NULL),
(581, 1, 1, '<p>TABLE RÉFECTOIRE AVEC BANQUETTE</p>', '<p>TABLE RÉFECTOIRE AVEC BANQUETTE </p>\n<p><strong><br />Dimension:</strong> Table 180*70H75.<br />banquette : 180*35.<br /><strong>Nombre de pièces:</strong> 3 ( 2 banquettes + 1table ): 680 dt couleur blanc</p>\n<p>Autre couleur : 770 dt </p>\n<p><strong>Dimension:</strong> Table 200*80H75.<br />banquette : 200*35.</p>\n<p><strong>Nombre de pièces:</strong> 3 ( 2 banquettes + 1table ): 730 dt couleur blanc</p>\n<p>Autre couleur : 825 dt </p>', 'table-refectoire-avec-banquette-18070', 'TABLE RÉFECTOIRE AVEC BANQUETTE   Table de refectoire ou de cantine, spécialement conçues pour être robuste et destinée à l\'aménagement des réfectoires.', NULL, 'TABLE RÉFECTOIRE AVEC BANQUETTE - TABLE - lart du meuble rades ', 'TABLE RÉFECTOIRE AVEC BANQUETTE 180*70', NULL, NULL, NULL, NULL),
