(590, 1, 1, '<p>Dimensions : </p>\n<p>- Largeur : 90 cm</p>\n<p>- Profondeur : 38 cm</p>\n<p>- Hauteur : 187 cm</p>', '<p>Dimensions : </p>\n<p>- Largeur : 90 cm</p>\n<p>- Profondeur : 38 cm</p>\n<p>- Hauteur : 187 cm</p>', 'meuble-d-entree-ayos-noir', 'MEUBLE D\'ENTRÉE AYOS Noir / blanc meuble d\'entrée élément de rangement Console d\'entrée   ', NULL, 'MEUBLE D\'ENTRÉE AYOS élément d\'entrée Meuble d\'entre ', 'MEUBLE D\'ENTRÉE AYOS Noir', NULL, NULL, NULL, NULL),
(591, 1, 1, '<strong>PORTE MANTEAUX ELIX CHROMÉ</strong>\n<div class=\"product-information\">\n<div id=\"short_description_block\">\n<div id=\"short_description_content\" class=\"rte align_justify product-description-short-1\">\n<p>Pour finaliser votre décor intérieur du bureau! Le porte manteau Elix chromé constitué de 5 patères en PVC. Il est en métal chromé avec un porte parapluies en Pvc. Ce modèle s\'intégrera facilement dans votre bureau et utiliser pour éviter la déformation de vos vêtements. couleur chromé.</p>\n</div>\n</div>\n</div>', '<strong>PORTE MANTEAUX ELIX CHROMÉ</strong>\n<div class=\"product-information\">\n<div id=\"short_description_block\">\n<div id=\"short_description_content\" class=\"rte align_justify product-description-short-1\">\n<p>Pour finaliser votre décor intérieur du bureau! Le porte manteau Elix chromé constitué de 5 patères en PVC. Il est en métal chromé avec un porte parapluies en Pvc. Ce modèle s\'intégrera facilement dans votre bureau et utiliser pour éviter la déformation de vos vêtements. couleur chromé.</p>\n</div>\n</div>\n</div>', 'porte-manteaux-elix-chrome', 'PORTE MANTEAUX ELIX CHROMÉ A 05 crochets doubles A 04 crochets simples répartis sur les 4 cotés Une base solide et stable 1 colonne en métal chromée ', NULL, 'Porte manteau - rangement - porte vêtement - l\'art du meuble rades ', 'PORTE MANTEAUX ELIX CHROMÉ', NULL, NULL, NULL, NULL),
(592, 1, 1, '<p>La Tabouret de bureau ARCHITECTE a une assise est composé d\'un revètement Simili cuir vous donnant un confort remarquable. Cette Tabourt de bureau ARCHITECTE est d\'une grande solidité grâce à son carénage en ABS noir . Cette chaise est réglable en hauteur via un vérin. couleurs: tous les couleurs.</p>\n<p>NB : chaise avec patin ou roues selon choix du client </p>', '<p>La Tabouret de bureau ARCHITECTE a une assise est composé d\'un revètement Simili cuir vous donnant un confort remarquable. Cette Tabourt de bureau ARCHITECTE est d\'une grande solidité grâce à son carénage en ABS noir . Cette chaise est réglable en hauteur via un vérin. couleurs: tous les couleurs.</p>\n<p>NB : chaise avec patin ou roues selon choix du client </p>', 'tabouret-architecte-confort', 'La Tabouret de bureau ARCHITECTE a une assise et un dossier haut est composé d\'un revêtement Simili cuir vous donnant un confort remarquable. ', NULL, 'Tabouret Architecte confort - cuisine assise', 'Tabouret Architecte confort', NULL, NULL, NULL, NULL),
(593, 1, 1, '<div class=\"col-md-6\">\n<div class=\"images-container\">\n<div class=\"product-cover\">\n<div class=\"layer hidden-sm-down\">Dimensions ( H x L x P ) en cm:</div>\n<div class=\"layer hidden-sm-down\">- Lit : ( 132 x 277 x 220 ) ; Couchage : (160 x 200)</div>\n<div class=\"layer hidden-sm-down\">- Table De Nuit : (45 x 50 x 40)</div>\n<div class=\"layer hidden-sm-down\">- Chiffonniére : (82 x 110 x 45)</div>\n<div class=\"layer hidden-sm-down\">- Garde-Robe : (215 x 237 x 60)</div>\n</div>\n</div>\n</div>', '<div class=\"col-md-6\">\n<div class=\"images-container\">\n<div class=\"product-cover\">\n<div class=\"layer hidden-sm-down\">\n<p>Chambre à Coucher GLAMOUR</p>\n<p>Lit Glamour : 1000.000</p>\n<p>Chiffonnière Glamour : 550.000</p>\n<p>Garde-Robe Glamour : 1600.000</p>\n<p>Table de Nuit Glamour : 200.000</p>\n</div>\n</div>\n</div>\n</div>', 'chambre-a-coucher-glamour', 'Chambre à coucher Glamour Chambre parental chambrette suite parentale Lit: Tête de lit  Coiffeuse Table de nuit  Dressing', NULL, 'Chambre à coucher Glamour Chambre parental chambrette suite parentale', 'Chambre à coucher Glamour', NULL, NULL, NULL, NULL),
(594, 1, 1, '<p>La salle à manger SCONDINAVE blenz6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p> </p>', '<p>La salle à manger SCONDINAVE blenz6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p> </p>\n<p> </p>', 'salle-a-manger-scandinave-blenz-6-places', 'La salle à manger SCONDINAVE 6 places est parfaite pour meubler votre espace  Matiere : structure blenz  Dimensions:  Table: L 180 x H 82 x P 80 cm', NULL, 'La salle à manger SCONDINAVE 6 places Matière : structure blenz  ', 'Salle ?? Manger Scandinave Blenz 6 Places', NULL, NULL, NULL, NULL),
(595, 1, 1, '<p>Table a manger Gold Bois Blenz</p>\n<p>Dimension table : 180 / 90 cm </p>\n<p>matiere bois BLENZ </p>', '<p>Table a manger Gold Bois Blenz</p>\n<p>La table a manger scandinave tunisie Gold est une table aux finitions soignées. Son plateau a une finition au rendu doucement poudré. Les 6 chaises sont surélevées de 4 pieds d’inspiration nordiques.</p>\n<p>Dimension table : 180 / 90 cm </p>\n<p>matiere bois BLENZ </p>', 'table-a-manger-gold-bois-blenz', 'Table a manger Gold matlasse Bois Blenz  La table a manger scandinave Tunisie Gold. Les 6 chaises sont surélevées de 4 pied. matière bois BLENZ ', NULL, 'Table a manger Gold M Bois Blenz  La table a manger scandinave Tunisie', 'Table a manger Gold Bois Blenz', NULL, NULL, NULL, NULL),
(596, 1, 1, '<p>Assise et dossier en mousse 28/30. Revêtement en simili cuir. Accoudoirs en Polypropylène noir. Mécanisme, tournant, roulant, réglable en hauteur. Structure étoilée à 05 branches en Polypropylène couleur noir avec 05 roulettes tournantes roulantes.</p>\n<p>Couleur au choix </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>Assise et dossier en mousse 28/30. Revêtement en simili cuir. Accoudoirs en Polypropylène noir. Mécanisme, tournant, roulant, réglable en hauteur. Structure étoilée à 05 branches en Polypropylène couleur noir avec 05 roulettes tournantes roulantes.</p>\n<p>Couleur au choix </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'siege-paris', 'Assise et dossier en mousse 28/30. Revêtement en simili cuir. Accoudoirs en Polypropylène noir. Mécanisme, tournant, roulant, réglable en hauteur. ', NULL, 'SIÈGE PARIS GM chaise directeur Tunisie chaise ergonomique ', 'SIÈGE PARIS', NULL, NULL, NULL, NULL),
(597, 1, 1, '<p>CHAISE MONACO ECOTOP HD BASE CHROME 490.000 TTC <br /><br />CHAISE MONACO ECOTOP BD BASE CHROME 480.000TTC<br />Les couleurs disponibles en <br />NOIR/ BLANC / CAMEL</p>', '<p>CHAISE MONACO ECOTOP HD BASE CHROME 490.000 TTC<br /><br />CHAISE MONACO ECOTOP BD BASE CHROME 480.000TTC<br />Les couleurs disponibles en<br />NOIR/ BLANC / CAMEL</p>', 'monaco-ecotop-base-chromer', 'CHAISE MONACO ECOTOP HD BASE CHROME 500.000 TTC  CHAISE MONACO ECOTOP BD BASE CHROME 480.000TTC Les couleurs disponibles en NOIR/ BLANC / CAMEL', NULL, 'chaise - direction- bureautique - écolier - l\'art du meuble rades ', 'MONACO ECOTOP BASE CHROMER ', NULL, NULL, NULL, NULL),
(598, 1, 1, '<p>Cette salle à manger se compose :</p>\n<p>- Table + 4 Chaises dimension table 125/83 cm ou diamètre 90 cm</p>\n<p>- Table + 6 Chaises dimension table 180/83 cm ou diamètre 123 cm</p>\n<p>- Table + 8 Chaises dimension table 200/100 cm 150/150 cm</p>\n<p> </p>\n<p>NB : vous pouvez faire une dimension sur commande</p>\n<p>Matière : Structure Bois Rouge </p>\n<p>Couleur du bois et de tissu au choix </p>\n<p>Livraison payante selon adresse</p>', '<p>Cette salle à manger se compose :</p>\n<p>- Table + 4 Chaises dimension table 125/83 cm ou diamètre 90 cm</p>\n<p>- Table + 6 Chaises dimension table 180/83 cm ou diamètre 123 cm</p>\n<p>- Table + 8 Chaises dimension table 200/100 cm 150/150 cm</p>\n<p> </p>\n<p>NB : vous pouvez faire une dimension sur commande</p>\n<p>Matière : Structure Bois Rouge </p>\n<p>Couleur du bois et de tissu au choix </p>\n<p>Livraison payante selon adresse</p>', 'salle-a-manger-bois-model-capitonner-3-bondes-6-p-tr', 'salle-a-manger-structure-bois-model-capitonner-3-bondes-6-p L\'art du meuble rades Cette salle à manger se compose d\'une table de repas rectangulaire ou ronde', NULL, 'salle a manger - table - chaise - l\'art du meuble - meuble Tunisie', 'Salle a manger bois Model capitonner 3 Bondes 6 P TR', NULL, NULL, NULL, NULL),
(599, 1, 1, '<p>Bois massif :BLENZ</p>\n<p>dimension:L200*H83*P80</p>\n<p>Dimension matelas : L190*P70 </p>\n<p>NB: avec rangement (sandouk)</p>\n<p>le prix affiché est le prix de l\'unité</p>', '<p>Bois massif :BLENZ</p>\n<p>dimension:L200*H83*P80</p>\n<p>Dimension matelas : L190*P70 </p>\n<p>NB: avec rangement (sandouk)</p>\n<p>le prix affiché est le prix de l\'unité</p>', 'banquette-blenz-elegance-carreau', 'Banquette bois BLENZ Model élégance carreau Bois massif :BLENZ canapé élégance bois massif bois Tunisie', NULL, 'Banquette bois BLENZ Elegance - Canape massif', 'Banquette BLENZ Elegance Carreau', NULL, NULL, NULL, NULL),
(600, 1, 1, '<p>Chaise Salle de Fête confortable VIGO structure métallique epoxy</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Produit disponible en gros seulement </p>', '<p>Chaise Salle de Fête confortable VIGO structure métallique epoxy</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Carcasse en acier</p>\n<p>peinture epoxy couleur au choix</p>\n<p>Produit disponible en gros seulement </p>', 'chaise-salle-de-fete-vigo', 'chaise salle de conférence Chaise Salle de Fête confortable vigo Carcasse en acier  peinture epoxy couleur au choix', NULL, 'Chaise Salle de Fete VIGO - acier epoxy', 'Chaise Salle de Fête vigo ', NULL, NULL, NULL, NULL),
(601, 1, 1, '<p>Chaise Salle de Fête confortable VIGO structure métallique epoxy</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Produit disponible en gros seulement </p>', '<p>Chaise Salle de Fête confortable VIGO structure métallique epoxy</p>\n<p>Dimensions</p>\n<p>Largeur: 44 cm</p>\n<p>Profondeur: 54 cm</p>\n<p>Hauteur d’assise: 47 cm</p>\n<p>Hauteur: 94 cm</p>\n<p>Carcasse en acier</p>\n<p>peinture epoxy couleur au choix</p>\n<p>Produit disponible en gros seulement </p>', 'chaise-salle-de-fete-vigo-conique', 'chaise salle de conférence Chaise Salle de Fête confortable vigo Carcasse en acier  peinture epoxy couleur au choix', NULL, 'Chaise Salle de Fête vigo en acier  peinture epoxy conférence', 'Chaise Salle de Fête vigo conique', NULL, NULL, NULL, NULL),
(602, 1, 1, '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'fauteuil-de-bureau-bd-bomba', 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA Fauteuil de bureau ergonomique, équipé d\'un haut dossier, recommandé pour les postes ', NULL, 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA', 'Fauteuil de bureau BD BOMBA', NULL, NULL, NULL, NULL);
