(604, 1, 1, '<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">Le Brio moyen model est une chaise pivotante,<br />réglable en hauteur à dossier basculant.<br /></span></div>\n<div class=\"c5_fp_desc\"> </div>\n<div class=\"c5_fp_desc\"><strong>Couleur noir</strong></div>', '<div>\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">Le Brio moyen model est une chaise pivotante,<br />réglable en hauteur à dossier basculant.<br /></span></div>\n<div class=\"c5_fp_desc\"> </div>\n<div class=\"c5_fp_desc\"><strong>Couleur noir</strong></div>\n</div>\n<div class=\"c5_fp_desc\"> </div>', 'chaise-mm-piccolo-avec-accoudoirs', 'Chaise Piccolo moyen model est une chaise pivotante, réglable en hauteur à dossier basculant plusieurs coloris.', NULL, 'chaise - direction- bureautique - écolier - l\'art du meuble rades ', 'Chaise Secrétaire BRIO Haut Dossier Avec Accoudoirs', NULL, NULL, NULL, NULL),
(605, 1, 1, '<p>salle à manger Royal Bois blenz 6 places</p>\n<p>La salle à manger Royal Bois blenz 6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p>Dimensions:</p>\n<p>Table: L 180 x H 82 x P 90 cm</p>', '<p>salle à manger Royal Bois blenz 6 places</p>\n<p>La salle à manger Royal Bois blenz 6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p>Dimensions:</p>\n<p>Table: L 180 x H 82 x P 90 cm</p>', 'salle-a-manger-royal-bois-blenz-6-places-rectangle', 'salle à manger Royal Bois blenz 6 places  La salle à manger Royal Bois blenz 6 places est parfaite pour meubler votre espace  Matiere : structure blenz', NULL, 'salle à manger Royal Bois blenz 6 places salle a manger tunisie', 'salle à manger Royal Bois blenz 6 places', NULL, NULL, NULL, NULL),
(606, 1, 1, '<strong>Chaise de bureau Opérateur</strong>\n<p>Chaise de bureau Opérateur - Chaise confort, tournant, roulant avec accoudoirs et réglable en hauteur </p>\n<p>Tout les Couleurs</p>', '<strong>Chaise Opérateur avec accoudoirs </strong>\n<p>Chaise de bureau Opérateur - Chaise confort, tournant, roulant avec accoudoirs et réglable en hauteur </p>\n<p>Remarque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplémentaire</p>\n<p>Tout les Couleurs</p>', 'chaise-operateur-avec-accoudoirs', 'Chaise Opérateur avec accoudoirs  Chaise de bureau Opérateur - Chaise confort, tournant, roulant avec accoudoirs et réglable en hauteur ', NULL, 'Chaise Opérateur avec accoudoirs bureautique tunisie', 'Chaise Opérateur avec accoudoirs', NULL, NULL, NULL, NULL),
(607, 1, 1, '<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire</p>', '<p>fauteuil de bureau ergonomique</p>\n<ul><li>Mécanisme synchrone basculant</li>\n<li>Mousse Haute densité</li>\n<li>Régler la profondeur d’assise (translation d\'assise)</li>\n<li>Régler les accoudoirs</li>\n<li>Régler la hauteur du siège</li>\n<li>Régler l\'appui lombaire (support lombaire)</li>\n<li>Réglage de l\'inclinaison du dossier (tension d\'inclinaison réglable)</li>\n<li>Régler la tension du dossier</li>\n</ul>', 'chaise-ergonomique-seoul-argent', 'appuie-tête réglable support lombaire largeur de bras réglable  une hauteur de bras réglable assise réglable pour accompagner le support lombaire le réglag.....', NULL, 'chaise directeur Tunisie chaise ergonomique chaise confortable', 'Chaise ergonomique SEOUL Argent', NULL, NULL, NULL, NULL),
(608, 1, 1, '<p>Meuble à chaussure, Structure en panneaux de MDF 18mm - 86 x 103 x 38 cm – Revêtement en pvc , décor noyer américain - 2 portes battantes + 1 tiroir - Poignées  décor alu - Capacité 24 paires de chaussures - Livré monté.</p>\n<p>Modèle Stratifier couleurs disponible : Couleur blenc</p>\n<p> </p>', '<p>Meuble à chaussure, Structure en panneaux de MDF 18mm - 86 x 103 x 38 cm – Revêtement en pvc , décor noyer américain - 2 portes battantes + 1 tiroir - Poignées  décor alu - Capacité 24 paires de chaussures - Livré monté.</p>\n<p>Modèle Stratifier couleurs disponible :  Couleur blanc</p>\n<p> </p>', 'porte-chaussure-pvc', 'Meuble de chaussurePC21PVC, l\'art du meuble Tunisie, l\'Art du meuble, meuble Tunisie, meuble rades , porte chaussure, meuble et ameublement', NULL, 'Porte Chaussure PC21 L\'art du meuble Rades meuble meuble rangement', 'Porte Chaussure PVC', NULL, NULL, NULL, NULL),
