(671, 1, 1, '<p>MOLO </p>\n<div class=\"c5_fp_desc\">\n<div><br /><strong>MOLO </strong>un fauteuil de bureau ergonomique en tissu noir avec tous les réglages nécessaires pour une bonne position au bureau : tétière et accoudoirs réglable, basculant décentré de l\'assise et support lombaire .<br />Vous aurez aussi une mousse à très forte densité pour conserver une assise confortable durant toute la durée de vie de vie de votre siège de bureau.</div>\n</div>', '<p> </p>\n<div class=\"c5_fp_desc\"> \n<div><br /><strong>MOLO </strong>un fauteuil de bureau ergonomique en tissu noir avec tous les réglages nécessaires pour une bonne position au bureau : tétière et accoudoirs réglable, basculant décentré de l\'assise et support lombaire .<br /><br /></div>\n<div>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </div>\n</div>', 'chaise-molo', 'MOLO un fauteuil de bureau ergonomique en tissu noir avec tous les réglages nécessaires pour une bonne position au bureau : tétière et accoudoirs réglable', NULL, 'Chaise - bureautique - assise - bureau - l\'art du meuble rades', 'Chaise MOLO', NULL, NULL, NULL, NULL),
(672, 1, 1, '<p><br />CARACTÉRISTIQUES DE LA CHAISE ICE :<br />- Coque et accoudoirs en polypropylène.<br />- Assise et dossier en polyester.<br />- Densité mousse 30 kg/m³.<br />- Chaise réglable en hauteur par vérin à gaz.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>La chaise HORMA est une chaise de bureau<span class=\"st\"> de style,désign,trés tendance,bref c\'est une inspiration de haute qualité </span>.<br />Facilement maniable.</p>\n<p><br /><strong>Couleur :</strong> Noir</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-horma', 'Chaise ATLAMTA  La Chaise ATLANTA TUNISIE est une chaise économique basculante réglable en hauteur.', NULL, 'Chaise - bureautique - assise - bureau - l\'art du meuble rades', 'Chaise HORMA', NULL, NULL, NULL, NULL),
(673, 1, 1, '<p>Chaise Atlanta + acc</p>\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\"> une chaise operateur, basculante réglable en hauteur.<br /><strong>Couleur :</strong> similicuir de très bonne qualité<br /></span></div>', '<p>Chaise Atlanta + acc</p>\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">une chaise operateur, basculante réglable en hauteur.<br /><strong>Couleur :</strong> similicuir de très bonne qualité<br /></span></div>', 'chaise-atlanta-acc', 'Chaise Atlanta + acc\n<div class=\"c5_fp_desc\"><span id=\"ctl00_cp1_lab_desc\">une chaise operateur, basculante réglable en hauteur. <strong>Couleur :</strong>', NULL, 'Chaise Atlanta + acc', 'Chaise Atlanta + acc', NULL, NULL, NULL, NULL),
