(676, 1, 1, '<strong>BUREAU X-TIME</strong>\n<div class=\"print-desc\">BUREAU X-TIME PLATEAU EN Stratifies <br />PIEDS EN STRUCTURE METALLIQUE EPOXY BLANC<br />DIMENSION L=1.60 M P=75 CM H=73 CM : 510 dt </div>\n<div class=\"print-desc\">DIMENSION L=1.80 M P=75 CM H=73 CM : 550 dt </div>', '<strong>BUREAU X-TIME</strong>\n<div class=\"print-desc\">BUREAU X-TIME PLATEAU EN Stratifies <br />PIEDS EN STRUCTURE METALLIQUE EPOXY BLANC<br />DIMENSION L=1.60 M P=75 CM H=73 CM : 510 dt </div>\n<div class=\"print-desc\">DIMENSION L=1.80 M P=75 CM H=73 CM : 550 dt </div>', 'bureau-x-time-plateau-en-stratifies-pieds-en-structure-metallique-epoxy-blanc', 'BUREAU X-TIME PLATEAU EN Stratifier  PIEDS EN STRUCTURE METALLIQUE EPOXY BLANC', NULL, 'BUREAU X-TIME PLATEAU EN Stratifier ', 'BUREAU X-TIME PLATEAU EN Stratifies PIEDS EN STRUCTURE METALLIQUE EPOXY BLANC', NULL, NULL, NULL, NULL),
(677, 1, 1, '<p>salle à manger Bois blenz 6 places</p>\n<p>La salle à manger Bois blenz 6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p>Dimensions:</p>\n<p>Table: L 170 x H 82 x P 90 cm</p>', '<p>salle à manger Bois blenz 6 places</p>\n<p>La salle à manger Bois blenz 6 places est parfaite pour meubler votre espace</p>\n<p>Matiere : structure blenz</p>\n<p>Dimensions:</p>\n<p>Table: L 170 x H 82 x P 90 cm</p>', 'salle-a-manger-bondes-blenz-6-p', 'salle à manger Bois blenz 6 places  La salle à manger Bonde Bois blenz 6 places est parfaite pour meubler votre espace  Matiere : structure blenz', NULL, 'salle à manger Bois blenz 6 places salle a manger tunisie', 'salle à manger bondes blenz 6 p', NULL, NULL, NULL, NULL);
