(678, 1, 1, '<strong>Chaise Directeur HERO</strong>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Chaise Directeur HERO</strong>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-directeur-hero', 'Chaise Directeur HERO', NULL, 'Chaise Directeur HERO', 'Chaise Directeur HERO', NULL, NULL, NULL, NULL),
(679, 1, 1, '<p> </p>\n<strong>Chaise de Direction Moon</strong>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p> </p>\n<strong>Chaise de Direction Moon</strong>\n<p>Couleur disponible : </p>\n<p>- Noir </p>\n<p>- Gris </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-de-direction-moon', 'Chaise de Direction Moon', NULL, 'Chaise de Direction Moon', 'Chaise de Direction Moon', NULL, NULL, NULL, NULL),
(680, 1, 1, '<strong>Chaise de bureau SPIDER :Ergonomique, Confort ultime</strong>\n<p>Avantages :</p>\n<ul><li>Améliore la posture, réduisant les tensions musculaires</li>\n<li>Optimise la concentration et la productivité</li>\n<li>Personnalisable pour s’adapter à différentes morphologies</li>\n<li>Durable et facile d’entretien</li>\n</ul><p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Chaise de bureau SPIDER :Ergonomique, Confort ultime</strong>\n<p>Caractéristiques :</p>\n<ul><li>Conception ergonomique assurant un confort optimal</li>\n<li>Dossier en maille ventilée améliorant la circulation de l’air</li>\n<li>Siège rembourré en mousse haute densité pour un soutien lombaire</li>\n<li>Accoudoirs ajustables pour un soutien personnalisé</li>\n<li>Base en étoile robuste garantissant la stabilité</li>\n</ul>', 'chaise-de-bureau-spider', 'Chaise de bureau SPIDER : Ergonomique, Confort ultime', NULL, 'Chaise de bureau SPIDER : Ergonomique, Confort ultime', 'Chaise de bureau SPIDER', NULL, NULL, NULL, NULL),
(681, 1, 1, '<strong>Chaise de bureau KEY :</strong>\n<p><strong>Avantages</strong></p>\n<p>Soutien lombaire optimal pour réduire les douleurs dorsales Assise confortable pour des heures de travail prolongées Réglabilité pour un ajustement personnalisé Mobilité facile pour une utilisation polyvalente</p>', '<strong>Chaise de bureau KEY : Confort et style pour votre espace de travail</strong>\n<p><strong>Caractéristiques </strong></p>\n<p>Dossier ergonomique en maille respirante</p>\n<p>Siège rembourré en mousse haute densité</p>\n<p>Accoudoirs réglables en hauteur Base en nylon robuste avec roulettes silencieuses</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-de-bureau-key', 'Chaise de bureau KEY', NULL, 'Chaise de bureau KEY', 'Chaise de bureau KEY', NULL, NULL, NULL, NULL),
(682, 1, 1, '<strong>Chaise de bureau Tempo</strong>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Chaise de bureau Tempo</strong>\n<p>Chaise de bureau Tempo : confort ergonomique et style élégant pour votre espace de travail. Réglable en hauteur, accoudoirs rembourrés et dossier ergonomique pour un soutien optimal.</p>', 'chaise-de-bureau-tempo', 'Chaise de bureau Tempo', NULL, 'Chaise de bureau Tempo', 'Chaise de bureau Tempo', NULL, NULL, NULL, NULL),
(683, 1, 1, '<strong>Fauteuil ROY</strong>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil ROY</strong>\n<p>Fauteuil ROY : confort et élégance à l’état pur. Son design ergonomique épouse parfaitement les courbes du corps, offrant un soutien optimal. Son revêtement en cuir véritable garantit durabilité et toucher soyeux. Son piétement en bois massif apporte stabilité et touche naturelle.</p>', 'fauteuil-roy', 'Fauteuil ROY', NULL, 'Fauteuil ROY', 'Fauteuil ROY', NULL, NULL, NULL, NULL),
(685, 1, 1, '<p>Dimensions En Cm ( H x L x P ) :</p>\n<p>- Lit : ( 100 x 102 x 200 ); ( 100 x 132 x 200 ); ( 100 x 152 x 200 )</p>\n<p>- Table De Nuit : ( 100 x 50 x 40 ) - Garde Robe : ( 200 x 140 x 50 )</p>\n<p>- Bureau : ( 75 x 125 x 60 ) - Niche Bureau : ( 29 x 120 x 27 )</p>\n<p>- Elément De Rangement : ( 210 x 72 x 55 )</p>', '<p>Dimensions En Cm(H x L x P)</p>\n<p>- Lit :(100 x 102 x 200) :600 dt (DIM matelas :190/90cm)</p>\n<p>- Lit :(100 x 132 x 200) :650 dt (DIM matelas :190/120cm)</p>\n<p>- Table de nuit : 150 dt</p>\n<p>- Garde Robe:(200 x 140 x 50):850 dt</p>\n<p>- Bureau:(75 x 125 x 60):330 dt</p>\n<p>- Niche Bureau:(29 x 120 x 27):170 dt</p>\n<p>- Elément De Rangement:(210 x 72 x 55):430dt</p>', 'chambre-d-enfant-celina-rose', 'CHAMBRE D\'ENFANT CELINA - Lit - Table De Nuit - Garde Robe : ( 200 x 140 x 50 )  - Bureau : ( 75 x 125 x 60 ) - Niche Bureau - Elément De Rangement ', NULL, 'CHAMBRE D\'ENFANT CELINA chambre adulte l\'art du meuble rades ', 'CHAMBRE D\'ENFANT CELINA ROSE', NULL, NULL, NULL, NULL),
(686, 1, 1, '<p>Caractéristique : chaise pivotante et mobile. </p>\n<p>Couleur au choix </p>\n<p>Note : Le coût indiqué pour le produit est basé sur une base noire, sinon une base chromée entraîne un supplément de 40 dt. </p>', '<strong>Chaise attente ISO 1 place roulant</strong>\n<p>Caractéristique : chaise pivotante et mobile. </p>\n<p>Couleur au choix </p>\n<p> </p>', 'chaise-attente-iso-1-place-roulant', 'Chaise attente ISO 1 place roulant Caractéristique : chaise pivotante et mobile.   Couleur au choix ', NULL, 'Chaise attente ISO 1 place roulant', 'Chaise attente ISO 1 place roulant', NULL, NULL, NULL, NULL),
(687, 1, 1, '<p>Caractéristique : chaise pivotante et mobile. </p>\n<p>Couleur au choix </p>\n<p>Note : Le coût indiqué pour le produit est basé sur une base noire, sinon une base chromée entraîne un supplément de 40 dt. </p>', '<strong>Chaise attente ISO 1 place roulant avec tablette </strong>\n<p>Caractéristique : chaise pivotante et mobile. </p>\n<p>Couleur au choix </p>\n<p> </p>', 'chaise-attente-iso-1-place-roulant-avec-tablette', 'Chaise attente ISO 1 place roulant avec tablette Caractéristique : chaise pivotante et mobile.   Couleur au choix ', NULL, 'Chaise attente ISO 1 place roulant avec tablette', 'Chaise attente ISO 1 place roulant avec tablette ', NULL, NULL, NULL, NULL),
