(693, 1, 1, '<p>Pied de Chaise de bureau 5 branches, diamètre 64 cm, pour roulettes ou patins, en acier chromé</p>', '<p>Pied de Chaise de bureau 5 branches en acier chromé</p>', 'pied-de-chaise-de-bureau-5-branches-diametre-64-cm-en-acier-chrome', 'Pied de Chaise de bureau 5 branches, diamètre 64 cm, pour roulettes ou patins, en acier chromé', NULL, 'Pied de Chaise de bureau 5 branches, en acier chromé', 'Pied de Chaise de bureau 5 branches, diamètre 64 cm en acier chromé', NULL, NULL, NULL, NULL),
(694, 1, 1, '<p> </p>\n<p>Pied de Chaise de bureau waytex Nylon noir - Compatible roulettes et patins - Diamètre 64 cm</p>', '<p>Pied de Chaise de bureau waytex Nylon noir - Compatible roulettes et patins - Diamètre 64 cm</p>', 'pied-de-chaise-de-bureau-nylon-noir-diametre-64-cm', 'Pied de Chaise de bureau Nylon noir - Compatible roulettes et patins - Diamètre 64 cm', NULL, 'Pied de Chaise de bureau Nylon noir Diamètre 64 cm', 'Pied de Chaise de bureau Nylon noir Diamètre 64 cm', NULL, NULL, NULL, NULL),
(695, 1, 1, '<p> </p>\n<p>Pied de Chaise de bureau waytex Nylon noir - Compatible roulettes et patins - Diamètre 56 cm</p>', '<p>Pied de Chaise de bureau waytex Nylon noir - Compatible roulettes et patins - Diamètre 56 cm</p>', 'pied-de-chaise-de-bureau-nylon-noir-diametre-56-cm', 'Pied de Chaise de bureau Nylon noir - Compatible roulettes et patins - Diamètre 56 cm', NULL, 'Pied de Chaise de bureau Nylon noir Diamètre 56 cm', 'Pied de Chaise de bureau Nylon noir Diamètre 56 cm', NULL, NULL, NULL, NULL),
(696, 1, 1, '<p>Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 27,5 à 39,5 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm. La longueur du cylindre interne est de 120 mm. Il est facile à installer et à utiliser.</p>', '<p>Vérin de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir</p>\n<p class=\"product_title entry-title\">Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 27,5 à 39,5 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm.</p>\n<p class=\"product_title entry-title\"> </p>', 'verin-de-rechange-pour-chaise-de-bureau', 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir', NULL, 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur', 'Vérin de rechange pour chaise de bureau', NULL, NULL, NULL, NULL),
(697, 1, 1, '<p>Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 25 à 34 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm. La longueur du cylindre interne est de 120 mm. Il est facile à installer et à utiliser.</p>', '<p>Vérin Métal chromé de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir</p>\n<p class=\"product_title entry-title\">Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 25 à 34 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm.</p>\n<p class=\"product_title entry-title\"> </p>', 'verin-metal-chrome-rechange-fauteuil-bureau', 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir', NULL, 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur', 'Vérin Métal chromé de rechange pour fauteuil de bureau', NULL, NULL, NULL, NULL),
(698, 1, 1, NULL, '<p>jeu de 5 roulettes universelles noires pour fauteuil est fabriqué en plastique et mesure 11/50mm. Il est vendu par lot de 5</p>', 'jeu-de-5-roulettes-universelles-noires-pour-fauteuil', 'jeu de 5 roulettes universelles noires pour fauteuil est fabriqué en plastique et mesure 11/50mm. Il est vendu par lot de 5', NULL, 'jeu de 5 roulettes universelles noires pour fauteuil', 'jeu de 5 roulettes universelles noires pour fauteuil', NULL, NULL, NULL, NULL),
(700, 1, 1, '<p>Lot de 5 pieds fixes pour chaise de bureau – Hauteur 3,5 cm – Usage sur tous types de sols – Diamètre tige clipsable standard 11mm – Compatibles avec tous les fauteuils de bureau et de toutes marques</p>', '<p>Lot de 5 pieds fixes pour chaise de bureau – Hauteur 3,5 cm – Usage sur tous types de sols – Diamètre tige clipsable standard 11mm – Compatibles avec tous les fauteuils de bureau et de toutes marques</p>', 'lot-de-5-pieds-fixes-pour-chaise-de-bureau', 'Lot de 5 pieds fixes pour chaise de bureau – Hauteur 3,5 cm – Usage sur tous types de sols – Diamètre tige clipsable standard 11mm – Compatibles ', NULL, 'Lot de 5 pieds fixes pour chaise de bureau – Hauteur 3,5 cm', 'Lot de 5 pieds fixes pour chaise de bureau', NULL, NULL, NULL, NULL),
(701, 1, 1, '<p>Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 25 à 34 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm. La longueur du cylindre interne est de 120 mm. Il est facile à installer et à utiliser.</p>', '<p>Vérin de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir</p>\n<p class=\"product_title entry-title\">Ce vérin pneumatique noir de 120mm est conçu pour les fauteuils et/ou chaises de bureau. Il est réglable en hauteur de 25 à 34 cm et convient à tous les fauteuils de bureau grâce à son caractère universel. Le diamètre du cylindre intérieur est de 25 mm et celui du cylindre extérieur est de 50 mm.</p>\n<p class=\"product_title entry-title\"> </p>', 'verin-de-rechange-pour-fauteuil-de-bureau', 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur - Universel - Noir', NULL, 'Vérin de rechange pour fauteuil de bureau - Réglable en hauteur', 'Vérin de rechange pour fauteuil de bureau', NULL, NULL, NULL, NULL),
(702, 1, 1, '<strong>Fauteuil de bureau ergonomique à dossier rembourré avec têtière </strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil de bureau ergonomique à dossier rembourré avec têtière </strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<ul><li>Assise et dossier en simili cuir couleur noir</li>\n<li>Avec accoudoirs</li>\n<li>Réglable en hauteur et en inclinaison</li>\n<li>Base étoile 5 branches PVC noir ou métalliques chromés, sur roulettes</li>\n</ul>', 'fauteuil-ergonomique-avion-tetiere-grege', 'Fauteuil de bureau ergonomique à dossier rembourré avec têtière Chaise de bureau Tunisie grege', NULL, 'Fauteuil de bureau ergonomique AVION tetiere Grege', 'FAUTEUIL ERGONOMIQUE AVION têtière Grège', NULL, NULL, NULL, NULL),
(703, 1, 1, '<strong>Fauteuil de bureau ergonomique à dossier rembourré avec têtière </strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil de bureau ergonomique à dossier rembourré avec têtière </strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<ul><li>Assise et dossier en simili cuir couleur noir</li>\n<li>Avec accoudoirs</li>\n<li>Réglable en hauteur et en inclinaison</li>\n<li>Base étoile 5 branches PVC noir ou métalliques chromés, sur roulettes</li>\n</ul>', 'fauteuil-ergonomique-avion-tetiere-caramel', 'Fauteuil de bureau ergonomique à dossier rembourré avec têtière Chaise de bureau Tunisie  Carmel', NULL, 'Fauteuil de bureau ergonomique AVION tetiere Caramel', 'FAUTEUIL ERGONOMIQUE AVION têtière Caramel', NULL, NULL, NULL, NULL),
(704, 1, 1, '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA Caramel</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA Caramel</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'fauteuil-de-bureau-bd-bomba-caramel', 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA Fauteuil de bureau ergonomique, équipé d\'un haut dossier, recommandé pour les postes  Caramel', NULL, 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA Caramel', 'Fauteuil de bureau BD BOMBA Caramel', NULL, NULL, NULL, NULL),
(705, 1, 1, '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA Grège</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<strong>Fauteuil de bureau ergonomique à dossier rembourré BOMBA Grège</strong>\n<p><strong>Fauteuil de bureau ergonomique</strong>, équipé d’un <strong>haut dossier</strong>, recommandé pour les postes qui nécessitent de s’asseoir une <strong>longue durée</strong>.</p>\n<p> </p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'fauteuil-de-bureau-bd-bomba-grege', 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA Fauteuil de bureau ergonomique, équipé d\'un haut dossier, recommandé pour les postes  Grège', NULL, 'Fauteuil de bureau ergonomique à dossier rembourré BOMBA Grège', 'Fauteuil de bureau BD BOMBA Grège ', NULL, NULL, NULL, NULL),
(706, 1, 1, '<div class=\"product-prices\">\n<div class=\"product-price h5\">\n<div class=\"current-price\">TABLE BASSE Model Droite</div>\n<div class=\"current-price\"> </div>\n<div class=\"current-price\">Dimensions :</div>\n</div>\n</div>\n<div class=\"product-information\">\n<div id=\"product-description-short-134\">\n<p>-Largeur : 83 cm </p>\n<p>-Profondeur : 83 cm</p>\n<p>-Hauteur : 35 cm </p>\n<p> </p>\n</div>\n</div>', '<div class=\"product-prices\">\n<div class=\"product-price h5\">\n<div class=\"current-price\">TABLE BASSE Model Droite</div>\n<div class=\"current-price\"> </div>\n<div class=\"current-price\">Dimensions :</div>\n</div>\n</div>\n<div class=\"product-information\">\n<div id=\"product-description-short-134\">\n<p>-Largeur : 83 cm </p>\n<p>-Profondeur : 83 cm</p>\n<p>-Hauteur : 35 cm </p>\n<p> </p>\n</div>\n</div>', 'table-basse-carre-model-droite', 'TABLE BASSE RECTANGULAIRE ACAJOU  Dimensions : -Largeur : 102 cm   -Profondeur : 60 cm  -Hauteur : 35 cm   Bois Hêtre BLENZ', NULL, 'table basse table basse tunisie Lart du meuble rades ', 'TABLE BASSE CARRE Model Droite', NULL, NULL, NULL, NULL),
(708, 1, 1, '<p>Bois massif :BLENZ</p>\n<p>dimension:L200*H83*P80</p>\n<p>Dimension matelas : L190*P70 </p>\n<p>NB: avec rangement (sandouk)</p>\n<p>le prix affiché est le prix de l\'unité</p>', '<p>Bois massif :BLENZ</p>\n<p>dimension:L200*H83*P80</p>\n<p>Dimension matelas : L190*P70 </p>\n<p>NB: avec rangement (sandouk)</p>\n<p>le prix affiché est le prix de l\'unité</p>', 'banquette-bois-blenz-model-droite', 'Banquette bois BLENZ Model Droite', NULL, 'Banquette bois BLENZ Model DROITE', 'Banquette bois BLENZ Model DROITE', NULL, NULL, NULL, NULL),
(709, 1, 1, '<p>Chambre à Coucher DIVA 2</p>\n<p>Lit DIVA 1m60  500.010</p>\n<p>Table De Nuit DIVA  130.000</p>\n<p>Chiffonnière DIVA  450.000</p>\n<p>Garde-robe DIVA 6 Porte  1 300.000</p>\n<p>Garde-robe DIVA 5 Porte   1 150.000</p>\n<p>NB : </p>\n<p>Chambre à Coucher DIVA Garde-robe  5 Porte : 2200.000</p>\n<p>Chambre à Coucher DIVA Garde-robe  6 Porte : 2350.000</p>', '<p>Chambre à Coucher DIVA 2</p>\n<p>Lit DIVA 1m60  500.010</p>\n<p>Table De Nuit DIVA  130.000</p>\n<p>Chiffonnière DIVA  450.000</p>\n<p>Garde-robe DIVA 6 Porte  1 300.000</p>\n<p>Garde-robe DIVA 5 Porte   1 150.000</p>\n<p>NB : </p>\n<p>Chambre à Coucher DIVA Garde-robe  5 Porte : 2200.000</p>\n<p>Chambre à Coucher DIVA Garde-robe  6 Porte : 2350.000</p>', 'chambre-a-coucher-diva-2', 'CHAMBRE À COUCHER TOKYO - Lit : ( 113 x238 x 210)   - Table de nuit : ( 44 x 60 x 40)  - Garde robe : ( 208x240 x60)  - Chiffonnière : (73*130*57)', NULL, 'CHAMBRE À COUCHER TOKYO Lit Table De Nuit Chiffonnière Garde Robe', 'Chambre à Coucher DIVA 2', NULL, NULL, NULL, NULL),
(710, 1, 1, '<p>CARACTÉRISTIQUES DE LA CHAISE ICE :<br />- Coque et accoudoirs en polypropylène.<br />- Assise et dossier en polyester.<br />- Densité mousse 30 kg/m³.<br />- Chaise réglable en hauteur par vérin à gaz.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>La chaise LEVO est une chaise de bureau<span class=\"st\"> de style,désign,trés tendance,bref c\'est une inspiration de haute qualité </span>.<br />Facilement maniable.</p>\n<p><br /><strong>Couleur :</strong> Noir</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-direction-levo', 'La chaise LEVO est une chaise de bureau de style,désign,trés tendance,bref c\'est une inspiration de haute qualité . Facilement maniable.', NULL, 'Chaise LEVO', 'Chaise direction Levo ', NULL, NULL, NULL, NULL),
(711, 1, 1, '<p>CARACTÉRISTIQUES DE LA CHAISE ICE :<br />- Coque et accoudoirs en polypropylène.<br />- Assise et dossier en polyester.<br />- Densité mousse 30 kg/m³.<br />- Chaise réglable en hauteur par vérin à gaz.</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', '<p>La chaise HORMA avec teitire est une chaise de bureau<span class=\"st\"> de style,désign,trés tendance,bref c\'est une inspiration de haute qualité </span>.<br />Facilement maniable.</p>\n<p><br /><strong>Couleur :</strong> Noir</p>\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 40 dt supplementaire </p>', 'chaise-horma-avec-tetere', 'CARACTÉRISTIQUES DE LA CHAISE ICE : - Coque et accoudoirs en polypropylène. - Assise et dossier en polyester. - Densité mousse 30 kg/m³.', NULL, 'Chaise Horma Avec Têtière ', 'Chaise HORMA avec Tetere', NULL, NULL, NULL, NULL),
(712, 1, 1, '<p> </p>\r\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 30 dt supplementaire </p>', '<div class=\"elementor-element elementor-element-7f55078 elementor-widget elementor-widget-heading\"> </div>\r\n<div class=\"elementor-element elementor-element-38f55ea elementor-widget elementor-widget-text-editor\">\r\n<div class=\"elementor-widget-container\">\r\n<p class=\"p1\">Le <span class=\"s1\">fauteuil de bureau Vega</span> associe <span class=\"s1\">confort respirant</span>, <span class=\"s1\">design moderne</span> et <span class=\"s1\">fonctionnalité essentielle</span> pour ceux qui recherchent un siège fiable au quotidien. Son <span class=\"s1\">dossier en maille aérée</span>, et son <span class=\"s1\">mécanisme basculant centré</span>. Sa <span class=\"s1\">mousse de qualité (32 kg/m³)</span> et sa <span class=\"s1\">structure robuste</span>. C’est un fauteuil pensé pour allier un <span class=\"s1\">excellent rapport qualité/prix</span>.</p>\r\n</div>\r\n</div>', 'chaise-vega-avec-tetiere-tissu', 'Le fauteuil de bureau Vega associe confort respirant, design moderne et fonctionnalité essentielle pour ceux qui recherchent un siège fiable au quotidien.', '', 'Chaise vega avec têtière', 'Chaise VEGA Avec Têtière', '', '', '', ''),
(713, 1, 1, '<p> </p>\r\n<p>Remaque : le prix afficher du produit avec une base Noir sinon base chromer + 30 dt supplementaire </p>', '<div class=\"elementor-element elementor-element-7f55078 elementor-widget elementor-widget-heading\"> </div>\r\n<div class=\"elementor-element elementor-element-38f55ea elementor-widget elementor-widget-text-editor\">\r\n<div class=\"elementor-widget-container\">\r\n<p class=\"p1\">Le <span class=\"s1\">fauteuil de bureau Vega</span> associe <span class=\"s1\">confort respirant</span>, <span class=\"s1\">design moderne</span> et <span class=\"s1\">fonctionnalité essentielle</span> pour ceux qui recherchent un siège fiable au quotidien. Son <span class=\"s1\">dossier en maille aérée</span>, et son <span class=\"s1\">mécanisme basculant centré</span>. Sa <span class=\"s1\">mousse de qualité (32 kg/m³)</span> et sa <span class=\"s1\">structure robuste</span>. C’est un fauteuil pensé pour allier un <span class=\"s1\">excellent rapport qualité/prix</span>.</p>\r\n</div>\r\n</div>', 'chaise-vega-avec-tetiere-cuir', 'Le fauteuil de bureau Vega associe confort respirant, design moderne et fonctionnalité essentielle pour ceux qui recherchent un siège fiable au quotidien.', '', 'Chaise vega', 'Chaise VEGA', '', '', '', '');
